function icon(name, cls = '') {
  return `<span class="icon ${cls}" aria-hidden="true">${ICONS[name] || ''}</span>`;
}
/* ============================================================
   I18N + GLOBAL STATE
   ============================================================ */
const APP = {
  lang: localStorage.getItem('inry_lang') || 'fr',
  theme: localStorage.getItem('inry_theme') || 'light',
  db: null,
  i18n: null,
  filters: {
    level: '',
    levelGroup: '',
    stream: '',
    subject: '',
    type: '',
    trimestre: '',
    year: '',
    search: ''
  }
};

function t(path) {
  const dict = APP.i18n[APP.lang];
  const parts = path.split('.');
  let cur = dict;
  for (const p of parts) {
    if (cur && typeof cur === 'object' && p in cur) cur = cur[p];
    else return path;
  }
  return cur;
}

function localized(field) {
  if (!field) return '';
  if (typeof field === 'string') return field;
  return field[APP.lang] || field.fr || Object.values(field)[0] || '';
}

async function loadData() {
  var cdn = window.SCHOOL_GITHUB_CDN;
  if (cdn) {
    try {
      var [dbRes, i18nRes] = await Promise.all([
        fetch(cdn + '/data/db.json?v=' + Date.now(), { cache: 'no-store' }),
        fetch(cdn + '/data/i18n.json?v=' + Date.now(), { cache: 'no-store' })
      ]);
      if (dbRes.ok) APP.db = await dbRes.json();
      else APP.db = window.INRY_DB;
      if (i18nRes.ok) APP.i18n = await i18nRes.json();
      else APP.i18n = window.INRY_I18N;
    } catch (e) {
      console.warn('[School-Biblio] CDN indisponible, fallback embarqué');
      APP.db = window.INRY_DB;
      APP.i18n = window.INRY_I18N;
    }
  } else {
    APP.db = window.INRY_DB;
    APP.i18n = window.INRY_I18N;
  }

  // Load hidden IDs from remote db.json if available and local storage is empty
  if (APP.db && APP.db.hidden) {
    var h = APP.db.hidden;
    if (getHiddenIds().length === 0 && h.docIds && h.docIds.length) saveHiddenIds(h.docIds);
    if (getEntityHiddenIds('levels').length === 0 && h.levelIds && h.levelIds.length) saveEntityHiddenIds('levels', h.levelIds);
    if (getEntityHiddenIds('streams').length === 0 && h.streamIds && h.streamIds.length) saveEntityHiddenIds('streams', h.streamIds);
    if (getEntityHiddenIds('subjects').length === 0 && h.subjectIds && h.subjectIds.length) saveEntityHiddenIds('subjects', h.subjectIds);
    if (getEntityHiddenIds('documentTypes').length === 0 && h.documentTypeIds && h.documentTypeIds.length) saveEntityHiddenIds('documentTypes', h.documentTypeIds);
  }
  if (APP.db && APP.db.githubSync && !localStorage.getItem('inry_github_sync')) {
    var gs = APP.db.githubSync;
    localStorage.setItem('inry_github_sync', JSON.stringify({
      repo: gs.repo || '',
      branch: gs.branch || 'main',
      path: gs.path || 'repo/data/db.json'
    }));
    if (gs.patKey) localStorage.setItem('fp_gh_pat_key', gs.patKey);
    if (gs.encryptedPAT && gs.patKey) {
      try {
        var keyBytes = Uint8Array.from(atob(gs.patKey), function(c) { return c.charCodeAt(0); });
        var cryptoKey = await crypto.subtle.importKey('raw', keyBytes, 'AES-GCM', false, ['decrypt']);
        var iv = Uint8Array.from(atob(gs.encryptedPAT.iv), function(c) { return c.charCodeAt(0); });
        var data = Uint8Array.from(atob(gs.encryptedPAT.data), function(c) { return c.charCodeAt(0); });
        var dec = await crypto.subtle.decrypt({ name: 'AES-GCM', iv: iv }, cryptoKey, data);
        var pat = new TextDecoder().decode(dec);
        if (pat) {
          var savedCfg = JSON.parse(localStorage.getItem('inry_github_sync') || '{}');
          savedCfg.pat = pat;
          localStorage.setItem('inry_github_sync', JSON.stringify(savedCfg));
        }
      } catch(e) { console.warn('PAT decrypt from db.json failed:', e); }
    }
    if (gs.autoPush) localStorage.setItem('fp_github_auto_push', 'true');
  }
}

async function syncDbToGas(db) {
  const gasUrl   = window.SCHOOL_GAS_URL;
  const gasToken = window.SCHOOL_GAS_TOKEN;
  if (!gasUrl || !gasToken) return;
  try {
    const fd = new FormData();
    fd.append('token', gasToken);
    fd.append('db',    JSON.stringify(db));
    const res  = await fetch(gasUrl, { method: 'POST', body: fd });
    const json = await res.json();
    if (json.success) {
      console.log('[School-Biblio] GAS sync OK —', json.docs, 'docs');
      localStorage.removeItem('inry_custom_db');
      localStorage.removeItem('inry_local_docs');
      localStorage.removeItem('inry_deleted_ids');
    } else {
      console.warn('[School-Biblio] GAS sync erreur:', json.error);
    }
  } catch (e) {
    console.warn('[School-Biblio] GAS sync réseau échoué:', e.message);
  }
}

function applyLangToDocument() {
  const dir = APP.i18n[APP.lang].dir;
  document.documentElement.lang = APP.lang;
  document.documentElement.dir = dir;
  document.documentElement.setAttribute('data-theme', APP.theme);
}

function setLang(lang) {
  APP.lang = lang;
  localStorage.setItem('inry_lang', lang);
  applyLangToDocument();
  if (typeof onLangChange === 'function') onLangChange();
}

function setTheme(theme) {
  APP.theme = theme;
  localStorage.setItem('inry_theme', theme);
  document.documentElement.setAttribute('data-theme', theme);
}

function toggleTheme() {
  setTheme(APP.theme === 'light' ? 'dark' : 'light');
}

/* Generic helper: translate every [data-i18n] element using current dict */
function translateStaticDOM(root = document) {
  root.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    const val = t(key);
    if (val !== key) el.textContent = val;
  });
  root.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    const key = el.getAttribute('data-i18n-placeholder');
    const val = t(key);
    if (val !== key) el.setAttribute('placeholder', val);
  });
}

function showToast(msg) {
  let toastEl = document.getElementById('global-toast');
  if (!toastEl) {
    toastEl = document.createElement('div');
    toastEl.id = 'global-toast';
    toastEl.className = 'toast';
    document.body.appendChild(toastEl);
  }
  toastEl.textContent = msg;
  toastEl.classList.add('show');
  clearTimeout(toastEl._timer);
  toastEl._timer = setTimeout(() => toastEl.classList.remove('show'), 2600);
}

function debounce(fn, delay) {
  let timer;
  return (...args) => {
    clearTimeout(timer);
    timer = setTimeout(() => fn(...args), delay);
  };
}
