let chatHistory = [];
let attachedFile = null;
let generationAbort = null;
let isGenerating = false;
function hasArabic(text) { return /[\u0600-\u06FF\u0750-\u077F\u08A0-\u08FF\uFB50-\uFDFF\uFE70-\uFEFF]/.test(text); }
function msgDir(text) { return hasArabic(text) ? 'rtl' : 'ltr'; }
function msgStyle(text) { return hasArabic(text) ? 'text-align:right;direction:rtl;unicode-bidi:isolate;' : 'text-align:left;direction:ltr;'; }

/* ---- Conversation management ---- */
const CONV_KEY = 'inry_conversations';
const CURR_CONV_KEY = 'inry_current_conv_id';
let conversations = [];
let currentConvId = null;

function loadConversations() {
  try { conversations = JSON.parse(localStorage.getItem(CONV_KEY) || '[]'); } catch { conversations = []; }
}
function saveConversations() {
  localStorage.setItem(CONV_KEY, JSON.stringify(conversations));
}

function saveCurrentConversation() {
  if (!currentConvId) return;
  const idx = conversations.findIndex(c => c.id === currentConvId);
  const title = conversations[idx]?.title || conversationTitleFromHistory() || 'Sans titre';
  const conv = { id: currentConvId, title, history: chatHistory, updated: Date.now() };
  if (idx >= 0) {
    conversations[idx] = conv;
  } else {
    conversations.push(conv);
  }
  saveConversations();
}

function conversationTitleFromHistory() {
  for (const m of chatHistory) {
    if (m.role === 'user' && m.content) {
      return m.content.slice(0, 60) + (m.content.length > 60 ? '…' : '');
    }
  }
  return '';
}

function switchConversation(id) {
  saveCurrentConversation();
  const conv = conversations.find(c => c.id === id);
  if (conv) {
    chatHistory = conv.history || [];
    currentConvId = id;
  } else {
    chatHistory = [];
    currentConvId = null;
  }
  localStorage.setItem(CURR_CONV_KEY, currentConvId || '');
  renderChatHistory();
  renderConvList();
}

function newConversation() {
  saveCurrentConversation();
  chatHistory = [];
  currentConvId = 'conv-' + Date.now();
  conversations.push({ id: currentConvId, title: 'Nouvelle conversation', history: [], created: Date.now(), updated: Date.now() });
  localStorage.setItem(CURR_CONV_KEY, currentConvId);
  saveConversations();
  renderChatHistory();
  renderConvList();
  document.getElementById('chat-search-inp').value = '';
  showFilteredChat = false;
}

function deleteConversation(id) {
  conversations = conversations.filter(c => c.id !== id);
  saveConversations();
  if (currentConvId === id) {
    if (conversations.length > 0) {
      switchConversation(conversations[conversations.length - 1].id);
    } else {
      newConversation();
    }
  } else {
    renderConvList();
  }
}

function renameConversation(id, newTitle) {
  const conv = conversations.find(c => c.id === id);
  if (conv) { conv.title = newTitle || 'Sans titre'; conv.updated = Date.now(); saveConversations(); renderConvList(); }
}

function renderConvList() {
  const list = document.getElementById('conv-list');
  if (!list) return;
  if (!conversations.length) {
    list.innerHTML = '<div style="padding:var(--space-3);font-size:var(--fs-xs);color:var(--ink-soft);text-align:center;">Aucune conversation</div>';
    return;
  }
  list.innerHTML = [...conversations].sort((a, b) => (b.updated || 0) - (a.updated || 0)).map(c =>
    `<div class="conv-item ${c.id === currentConvId ? 'active' : ''}" data-conv-id="${c.id}">
      <span class="conv-item-title">${escapeHTML(c.title || 'Sans titre')}</span>
      <span class="conv-item-actions">
        <button class="conv-rename-btn" title="Renommer">✎</button>
        <button class="conv-delete-btn" title="Supprimer">✕</button>
      </span>
    </div>`
  ).join('');
  list.querySelectorAll('.conv-item').forEach(el => {
    el.addEventListener('click', (e) => {
      if (e.target.closest('.conv-item-actions')) return;
      switchConversation(el.dataset.convId);
      document.getElementById('conv-sidebar').style.display = 'none';
    });
  });
  list.querySelectorAll('.conv-rename-btn').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      const id = btn.closest('.conv-item').dataset.convId;
      const title = prompt('Nouveau titre :', conversations.find(c => c.id === id)?.title || '');
      if (title !== null) renameConversation(id, title.trim());
    });
  });
  list.querySelectorAll('.conv-delete-btn').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      if (confirm('Supprimer cette conversation ?')) deleteConversation(btn.closest('.conv-item').dataset.convId);
    });
  });
}

/* ---- Saved prompts ---- */
const PROMPTS_KEY = 'inry_saved_prompts';
let savedPrompts = [];

function loadSavedPrompts() {
  try { savedPrompts = JSON.parse(localStorage.getItem(PROMPTS_KEY) || '[]'); } catch { savedPrompts = []; }
}
function saveSavedPrompts() {
  localStorage.setItem(PROMPTS_KEY, JSON.stringify(savedPrompts));
}
function addSavedPrompt(title, text) {
  savedPrompts.push({ id: 'prompt-' + Date.now(), title: title || 'Sans titre', text });
  saveSavedPrompts();
  renderPromptsList();
}
function deleteSavedPrompt(id) {
  savedPrompts = savedPrompts.filter(p => p.id !== id);
  saveSavedPrompts();
  renderPromptsList();
}
function renderPromptsList() {
  const list = document.getElementById('prompts-list');
  if (!list) return;
  if (!savedPrompts.length) {
    list.innerHTML = '<div style="padding:var(--space-3);font-size:var(--fs-xs);color:var(--ink-soft);text-align:center;">Aucun prompt sauvegardé</div>';
    return;
  }
  list.innerHTML = savedPrompts.map(p =>
    `<div class="prompt-item" data-prompt-text="${escapeHTML(p.text)}">
      <span class="prompt-item-text">${escapeHTML(p.title)}</span>
      <button class="prompt-delete-btn" style="background:none;border:none;cursor:pointer;font-size:10px;color:var(--red-stamp);" title="Supprimer">✕</button>
    </div>`
  ).join('');
  list.querySelectorAll('.prompt-item').forEach(el => {
    el.addEventListener('click', (e) => {
      if (e.target.closest('.prompt-delete-btn')) return;
      const ta = document.getElementById('chat-textarea');
      if (ta) {
        ta.value = el.dataset.promptText;
        ta.focus();
        ta.style.height = 'auto';
        ta.style.height = Math.min(ta.scrollHeight, 140) + 'px';
      }
      document.getElementById('saved-prompts-panel').style.display = 'none';
    });
  });
  list.querySelectorAll('.prompt-delete-btn').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      const el = btn.closest('.prompt-item');
      const idx = savedPrompts.findIndex(p => p.text === el.dataset.promptText);
      if (idx >= 0) deleteSavedPrompt(savedPrompts[idx].id);
    });
  });
}

/* ---- Export chat ---- */
function showExportMenu(anchor, cb) {
  var existing = document.getElementById('export-format-menu');
  if (existing) { existing.remove(); return; }
  var menu = document.createElement('div');
  menu.id = 'export-format-menu';
  menu.style.cssText = 'position:fixed;z-index:9999;background:var(--surface);border:2px solid var(--kraft);border-radius:var(--radius-md);box-shadow:0 4px 16px rgba(0,0,0,.12);padding:var(--space-1);display:flex;flex-direction:column;gap:2px;min-width:140px;opacity:0;pointer-events:none;';
  var rect = anchor.getBoundingClientRect();
  var items = [
    { icon: '📝', label: 'Markdown (.md)', fmt: 'md' },
    { icon: '📄', label: 'Texte (.txt)', fmt: 'txt' },
    { icon: '📘', label: 'Word (.doc)', fmt: 'doc' },
    { icon: '📕', label: 'PDF (.pdf)', fmt: 'pdf' }
  ];
  items.forEach(function(it) {
    var btn = document.createElement('button');
    btn.type = 'button';
    btn.style.cssText = 'display:flex;align-items:center;gap:var(--space-2);padding:var(--space-1) var(--space-3);border:none;border-radius:var(--radius-sm);background:transparent;color:var(--ink);font-size:var(--fs-xs);cursor:pointer;text-align:start;white-space:nowrap;';
    btn.innerHTML = '<span style="font-size:14px;">' + it.icon + '</span> ' + it.label;
    btn.onmouseover = function() { this.style.background = 'var(--cream-card)'; };
    btn.onmouseout = function() { this.style.background = 'transparent'; };
    btn.onclick = function() { menu.remove(); cb(it.fmt); };
    menu.appendChild(btn);
  });
  document.body.appendChild(menu);
  var mh = menu.offsetHeight;
  var top = rect.bottom + 4;
  if (top + mh > window.innerHeight) top = rect.top - mh - 4;
  top = Math.max(4, top);
  var left = Math.max(4, Math.min(rect.left, window.innerWidth - 160));
  menu.style.top = top + 'px';
  menu.style.left = left + 'px';
  menu.style.opacity = '';
  menu.style.pointerEvents = '';
  setTimeout(function() {
    document.addEventListener('click', function closeMenu(e2) {
      if (!menu.contains(e2.target)) { menu.remove(); document.removeEventListener('click', closeMenu); }
    });
  }, 10);
}

function exportChat(format, msgs) {
  msgs = msgs || chatHistory;
  if (!msgs.length) { showToast('Rien à exporter.'); return; }
  var lines = msgs.map(function(m) {
    var role = m.role === 'user' ? 'Vous' : 'Assistant';
    var prefix = m.fileName ? '[Fichier: ' + m.fileName + '] ' : '';
    var img = m.imgUrl ? '\n[Image générée]' : '';
    var date = m.timestamp ? new Date(m.timestamp).toLocaleString() : '';
    return '[' + (date || role) + '] ' + role + ': ' + prefix + m.content + img;
  }).join('\n---\n');
  var header = '# Conversation School-Biblio\n# ' + new Date().toLocaleString() + '\n\n';
  if (format === 'doc') {
    var docHtml = '<!DOCTYPE html><html><head><meta charset="utf-8"><title>Conversation School-Biblio</title></head><body style="font-family:sans-serif;max-width:700px;margin:auto;padding:2em;">' +
      '<h1 style="border-bottom:2px solid #ddd;padding-bottom:.5em;">Conversation School-Biblio</h1>' +
      '<p style="color:#666;font-size:.9em;">' + new Date().toLocaleString() + '</p>' +
      msgs.map(function(m) {
        var r = m.role === 'user' ? 'Vous' : 'Assistant';
        var c = m.content.replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>');
        return '<div style="margin:1em 0;padding:1em;background:' + (m.role === 'user' ? '#e8f5e9' : '#f5f5f5') + ';border-radius:8px;">' +
          '<strong>' + r + '</strong>' + (m.fileName ? ' <small>[' + m.fileName + ']</small>' : '') + '<br>' + c +
          (m.imgUrl ? '<br><em>[Image générée]</em>' : '') + '</div>';
      }).join('\n') + '</body></html>';
    var blob = new Blob([docHtml], { type: 'application/msword' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a'); a.href = url; a.download = 'conversation.doc';
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    URL.revokeObjectURL(url);
    return;
  }
  if (format === 'pdf') {
    var hasRtl = msgs.some(function(m) { return hasArabic(m.content); });
    try {
      if (typeof window.jspdf !== 'undefined' && !hasRtl) {
        var doc = new window.jspdf.jsPDF();
        var pageW = doc.internal.pageSize.getWidth();
        var margin = 20;
        var maxW = pageW - margin * 2;
        var y = margin;
        doc.setFontSize(16);
        doc.text('Conversation School-Biblio', margin, y);
        y += 8;
        doc.setFontSize(10);
        doc.setTextColor(100);
        doc.text(new Date().toLocaleString(), margin, y);
        y += 10;
        msgs.forEach(function(m) {
          if (y > doc.internal.pageSize.getHeight() - margin) { doc.addPage(); y = margin; }
          var r = m.role === 'user' ? 'Vous' : 'Assistant';
          var label = r + (m.fileName ? ' [' + m.fileName + ']' : '');
          doc.setFontSize(11);
          doc.setTextColor(m.role === 'user' ? '#2e7d32' : '#1565c0');
          doc.text(label, margin, y);
          y += 5;
          var textLines = doc.splitTextToSize(m.content, maxW);
          doc.setFontSize(10);
          doc.setTextColor(34);
          doc.text(textLines, margin, y);
          y += textLines.length * 5 + 6;
          if (m.imgUrl) {
            if (y > doc.internal.pageSize.getHeight() - margin) { doc.addPage(); y = margin; }
            doc.setTextColor(150);
            doc.text('[Image générée]', margin, y);
            y += 6;
          }
        });
        doc.save('conversation.pdf');
      } else {
        if (hasRtl && typeof window.jspdf === 'undefined') showToast('Contenu arabe — génération PDF via impression...');
        var pdfHtml = '<!DOCTYPE html><html dir="' + (hasRtl ? 'rtl' : 'ltr') + '"><head><meta charset="utf-8"><title>Conversation School-Biblio</title>' +
          '<style>body{font-family:sans-serif;max-width:700px;margin:auto;padding:2em;color:#222;}' +
          'h1{border-bottom:2px solid #ddd;padding-bottom:.5em;}' +
          '.msg{margin:1em 0;padding:1em;border-radius:8px;}' +
          '.user{background:#e8f5e9;text-align:' + (hasRtl ? 'right' : 'left') + ';}' +
          '.bot{background:#f5f5f5;text-align:' + (hasRtl ? 'right' : 'left') + ';}' +
          'small{color:#888;}@media print{body{padding:0;}}</style></head><body>' +
          '<h1>Conversation School-Biblio</h1>' +
          '<p style="color:#666;font-size:.9em;">' + new Date().toLocaleString() + '</p>' +
          msgs.map(function(m) {
            var r = m.role === 'user' ? 'Vous' : 'Assistant';
            var c = m.content.replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>');
            return '<div class="msg ' + (m.role === 'user' ? 'user' : 'bot') + '" dir="' + msgDir(m.content) + '">' +
              '<strong>' + r + '</strong>' + (m.fileName ? ' <small>[' + m.fileName + ']</small>' : '') + '<br>' + c +
              (m.imgUrl ? '<br><em>[Image générée]</em>' : '') + '</div>';
          }).join('\n') + '</body></html>';
        var w = window.open('', '_blank');
        if (w) { w.document.write(pdfHtml); w.document.close(); setTimeout(function() { w.focus(); w.print(); }, 500); }
      }
    } catch (e) { showToast('Erreur PDF : ' + e.message); }
    return;
  }
  var content = format === 'md' ? header + lines : lines.replace(/#/g, '');
  var ext = format === 'md' ? 'md' : 'txt';
  var blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a'); a.href = url; a.download = 'conversation.' + ext;
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

/* ---- Search in chat ---- */
let showFilteredChat = false;

function renderFilteredChat(query) {
  if (!query) { showFilteredChat = false; renderChatHistory(); return; }
  showFilteredChat = true;
  const scrollEl = document.getElementById('chat-scroll');
  const emptyEl = document.getElementById('chat-empty');
  const lower = query.toLowerCase();
  const filtered = chatHistory.filter(m => (m.content || '').toLowerCase().includes(lower) || (m.fileName || '').toLowerCase().includes(lower));
  if (!filtered.length) {
    scrollEl.innerHTML = '<div style="padding:var(--space-4);text-align:center;color:var(--ink-soft);font-size:var(--fs-sm);">Aucun message trouvé pour « ' + escapeHTML(query) + ' »</div>';
    emptyEl.classList.add('hidden');
    return;
  }
  emptyEl.classList.add('hidden');
  scrollEl.innerHTML = filtered.map(msg => {
    var contentHtml = (msg.role === 'bot' || msg.role === 'assistant') ? renderMarkdown(msg.content) : escapeHTML(msg.content);
    contentHtml = contentHtml.replace(new RegExp(escapeRegExp(query), 'gi'), m => '<mark style="background:var(--gold);color:var(--ink);padding:0 2px;border-radius:2px;">' + m.replace(/</g,'&lt;') + '</mark>');
    var copyHtml2 = (msg.role === 'bot' || msg.role === 'assistant') ? `<button class="copy-btn" onclick="copyMsgContent(this)">${icon('copy')} <span>Copier</span></button>` : '';
    return `<div dir="${msgDir(msg.content)}" style="${msgStyle(msg.content)}" class="chat-msg ${msg.role === 'user' ? 'user' : 'bot'}">${contentHtml}${copyHtml2}</div>`;
  }).join('');
  scrollEl.scrollTop = 0;
}

function escapeRegExp(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

/* ---- Original functions ---- */
function getSelectedKey() {
  const sel = document.getElementById('assistant-key-select');
  if (!sel) {
    var saved = sessionStorage.getItem('inry_assistant_key_id');
    if (saved && saved !== '__custom__') {
      var found = getStoredKeys().find(function(k) { return k.id === saved; });
      if (found) return found;
    }
    return getActiveKey();
  }
  const keyId = sel.value;
  if (!keyId) return null;
  if (keyId === '__custom__') {
    const customVal = document.getElementById('assistant-custom-key')?.value?.trim();
    const customProv = document.getElementById('assistant-custom-provider')?.value || 'openai';
    if (!customVal) return null;
    const defaults = PROVIDERS[customProv];
    if (defaults) {
      return { id: 'custom', provider: customProv, model: defaults.defaultModel, apiKey: customVal, endpoint: defaults.endpoint, active: true };
    }
    return { id: 'custom', provider: customProv, model: 'gpt-4.1', apiKey: customVal, active: true };
  }
  const keys = getStoredKeys();
  return keys.find(k => k.id === keyId) || null;
}

function populateKeySelect() {
  const sel = document.getElementById('assistant-key-select');
  const customRow = document.getElementById('assistant-custom-row');
  const customInput = document.getElementById('assistant-custom-key');
  const customProv = document.getElementById('assistant-custom-provider');
  if (!sel) { console.error('[populateKeySelect] sel not found'); return; }
  const keys = getStoredKeys();
  console.log('[DEBUG] getStoredKeys() returned', keys.length, 'keys:', JSON.stringify(keys).slice(0,200));
  const saved = sessionStorage.getItem('inry_assistant_key_id') || '';
  let html = `<option value="">${t('assistant.selectKey')}</option>`;
  if (keys.length === 0) {
    html += `<option value="" disabled style="color:var(--ink-soft);">— ${t('assistant.noKeysAvailable')} —</option>`;
  } else {
    keys.forEach(k => {
      const label = `${PROVIDERS[k.provider]?.label || k.provider} (${k.model})${k.endpoint ? ' · ' + k.endpoint : ''}`;
      html += `<option value="${k.id}" ${saved === k.id ? 'selected' : ''}>${label}</option>`;
    });
  }
  sel.dataset.empty = keys.length === 0 ? '1' : '0';

  var banner = document.getElementById('key-missing-banner');
  if (keys.length === 0) {
    if (!banner) {
      banner = document.createElement('div');
      banner.id = 'key-missing-banner';
      banner.style.cssText = 'background:var(--cream-card);border:1.5px dashed var(--gold);border-radius:var(--radius-md);padding:var(--space-3)var(--space-4);font-size:var(--fs-sm);color:var(--ink-soft);margin-bottom:var(--space-3);text-align:center;';
      banner.innerHTML = '🔑 ' + (t('assistant.noKeysHint') || 'Aucune clé API. Cliquez sur <strong>+</strong> ci-dessus pour en ajouter une.') + ' <button class="btn btn-secondary btn-sm" style="margin-inline-start:var(--space-2);" id="key-banner-add">+ Ajouter</button>';
      var keyRow = document.getElementById('assistant-key-select')?.parentNode;
      if (keyRow) keyRow.parentNode.insertBefore(banner, keyRow.nextSibling);
      document.getElementById('key-banner-add')?.addEventListener('click', function() {
        var p = document.getElementById('assistant-add-key-panel');
        if (p) { p.style.display = 'block'; banner.remove(); }
      });
    }
  } else {
    if (banner) banner.remove();
  }
  html += `<option value="__custom__" ${saved === '__custom__' ? 'selected' : ''}>— ${t('assistant.customKey')} —</option>`;
  sel.innerHTML = html;

  const showCustom = sel.value === '__custom__';
  if (customRow) customRow.style.display = showCustom ? 'flex' : 'none';
  if (customInput) customInput.style.display = showCustom ? '' : 'none';
  if (customProv) customProv.style.display = showCustom ? '' : 'none';

  if (showCustom && saved === '__custom__') {
    customInput.value = sessionStorage.getItem('inry_assistant_custom_key') || '';
    const savedProv = sessionStorage.getItem('inry_assistant_custom_provider');
    if (savedProv && customProv) customProv.value = savedProv;
  }

  if (keys.length === 0) {
    var panel = document.getElementById('assistant-add-key-panel');
    if (panel) panel.style.display = 'block';
  }

  sel.onchange = () => {
    const show = sel.value === '__custom__';
    if (customRow) customRow.style.display = show ? 'flex' : 'none';
    if (customInput) customInput.style.display = show ? '' : 'none';
    if (customProv) customProv.style.display = show ? '' : 'none';
    sessionStorage.setItem('inry_assistant_key_id', sel.value);
    if (!show) sessionStorage.removeItem('inry_assistant_custom_key');
    renderProviderPill();
  };
  if (customInput) {
    customInput.oninput = () => {
      sessionStorage.setItem('inry_assistant_custom_key', customInput.value);
      renderProviderPill();
    };
  }
  if (customProv) {
    customProv.onchange = () => {
      sessionStorage.setItem('inry_assistant_custom_provider', customProv.value);
      renderProviderPill();
    };
  }
  renderProviderPill();
}

function wireAddKeyPanel() {
  const toggleBtn = document.getElementById('assistant-add-key-btn');
  const panel = document.getElementById('assistant-add-key-panel');
  const provSel = document.getElementById('assistant-add-provider');
  const modelInput = document.getElementById('assistant-add-model');
  const endpointInput = document.getElementById('assistant-add-endpoint');
  const endpointRow = document.getElementById('assistant-add-endpoint-row');
  if (!toggleBtn || !panel) return;
  toggleBtn.onclick = () => {
    panel.style.display = panel.style.display === 'none' ? 'block' : 'none';
  };
  if (provSel && modelInput) {
    provSel.onchange = () => {
      const def = PROVIDERS[provSel.value];
      if (def && def.defaultModel) modelInput.value = def.defaultModel;
      if (endpointRow) {
        endpointRow.style.display = provSel.value === 'custom' ? '' : 'none';
      }
    };
  }
  document.getElementById('assistant-add-key-cancel').onclick = () => {
    panel.style.display = 'none';
  };
  document.getElementById('assistant-add-key-save').onclick = () => {
    const provider = document.getElementById('assistant-add-provider').value;
    const model = document.getElementById('assistant-add-model').value.trim();
    const apiKey = document.getElementById('assistant-add-apikey').value.trim();
    const endpoint = provider === 'custom' ? (endpointInput ? endpointInput.value.trim() : '') : '';
    if (!model || !apiKey) {
      showToast('Veuillez remplir le modèle et la clé API.');
      return;
    }
    if (provider === 'custom' && !endpoint) {
      showToast('Veuillez saisir l\'endpoint pour le fournisseur personnalisé.');
      return;
    }
    const keys = getStoredKeys();
    keys.push({
      id: 'key-' + Date.now(),
      provider,
      model,
      apiKey,
      endpoint: endpoint || undefined,
      active: keys.length === 0
    });
    saveStoredKeys(keys);
    document.getElementById('assistant-add-apikey').value = '';
    if (endpointInput) endpointInput.value = '';
    panel.style.display = 'none';
    populateKeySelect();
    const confirmEl = document.getElementById('assistant-add-key-confirm');
    confirmEl.classList.add('show');
    setTimeout(() => confirmEl.classList.remove('show'), 2000);
  };
}

function initAssistantPage() {
  loadConversations();
  loadSavedPrompts();
  const savedId = localStorage.getItem(CURR_CONV_KEY);
  if (savedId && conversations.find(c => c.id === savedId)) {
    switchConversation(savedId);
  } else if (conversations.length > 0) {
    switchConversation(conversations[conversations.length - 1].id);
  } else {
    newConversation();
  }
  populateKeySelect();
  renderProviderPill();
  renderChatHistory();
  renderConvList();
  renderPromptsList();
  wireAssistantEvents();
  wirePasswordToggle('assistant-custom-key');
  wirePasswordToggle('assistant-add-apikey');
  wireAddKeyPanel();
  wireToolbarEvents();
  createStopBtn();
}

function renderProviderPill() {
  const pillEl = document.getElementById('provider-pill');
  if (!pillEl) return;
  const active = getSelectedKey();
  if (active) {
    pillEl.classList.remove('off');
    const label = PROVIDERS[active.provider]?.label || active.provider || 'Clé personnelle';
    const modelInfo = active.model && active.provider !== 'custom' ? ' (' + active.model + ')' : '';
    const keySuffix = active.provider === 'custom' ? '' : '';
    pillEl.innerHTML = `<span class="dot"></span> ${t('assistant.providerLabel')}: ${escapeHTML(label)}${escapeHTML(modelInfo)}${escapeHTML(keySuffix)}`;
  } else {
    pillEl.classList.add('off');
    pillEl.innerHTML = `<span class="dot"></span> ${t('assistant.providerLabel')}: —`;
  }
}

function botMsgActions() {
  return `<button class="copy-btn" onclick="copyMsgContent(this)">${icon('copy')} <span>${t('assistant.copy')}</span></button>` +
         `<button class="regenerate-btn" onclick="regenerateLast()">${icon('refresh')} <span>${t('assistant.regenerate')}</span></button>`;
}

function renderRecentInEmpty() {
  var recent = getRecentDocs();
  var el = document.getElementById('chat-empty-recent');
  if (!el) return;
  if (!recent.length) { el.innerHTML = ''; return; }
  var items = recent.slice(0, 6).map(function(id) {
    var doc = (APP.db.documents || []).find(function(d) { return d.id === id; });
    if (!doc) return '';
    return '<li class="recent-item" data-doc-id="' + id + '">' + escapeHTML(localized(doc.title)) + '</li>';
  }).filter(Boolean);
  el.innerHTML = items.length ? '<h4 class="recent-heading">📖 Consultés récemment</h4><ul class="recent-list">' + items.join('') + '</ul>' : '';
  el.querySelectorAll('.recent-item').forEach(function(li) {
    li.addEventListener('click', function() { openDocModal(li.dataset.docId); });
  });
}

function renderChatHistory() {
  if (showFilteredChat) return;
  const scrollEl = document.getElementById('chat-scroll');
  const emptyEl = document.getElementById('chat-empty');
  if (!chatHistory.length) {
    scrollEl.innerHTML = '';
    emptyEl.classList.remove('hidden');
    renderRecentInEmpty();
    return;
  }
  emptyEl.classList.add('hidden');
  scrollEl.innerHTML = chatHistory.map(msg => {
    const extraClass = msg.fileName ? ' has-file' : '';
    const fileTag = msg.fileName ? `<div class="file-tag">${icon('paperclip')} ${escapeHTML(msg.fileName)}</div>` : '';
    var contentHtml;
    if (msg.role === 'bot' || msg.role === 'assistant') {
      try { contentHtml = renderMarkdown(msg.content); } catch(e) { console.error('[renderMarkdown]', e); contentHtml = escapeHTML(msg.content); }
    } else {
      contentHtml = escapeHTML(msg.content);
    }
    var imgHtml = msg.imgUrl ? `<img src="${escapeAttr(msg.imgUrl)}" alt="Généré" style="max-width:100%;border-radius:var(--radius-md);margin-top:var(--space-1);">` : '';
    var actionsHtml = (msg.role === 'bot' || msg.role === 'assistant') ? botMsgActions() : '';
    return `<div dir="${msgDir(msg.content)}" style="${msgStyle(msg.content)}" class="chat-msg ${msg.role === 'user' ? 'user' : 'bot'}${extraClass}">${fileTag}${contentHtml}${imgHtml}${actionsHtml}</div>`;
  }).join('');
  scrollEl.scrollTop = scrollEl.scrollHeight;
}

function escapeHTML(str) {
  var m = {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'};
  return String(str).replace(/[&<>"']/g, function(c) { return m[c]; });
}

function escapeAttr(str) {
  if (typeof str !== 'string') return '';
  return str.replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/'/g,'&#39;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

function renderMarkdown(text) {
  if (typeof text !== 'string') return '';
  var div = document.createElement('div');
  div.textContent = text;
  var html = div.innerHTML;

  var codeBlocks = [];
  html = html.replace(/<\/?br>/g, '\n');
  html = html.replace(/```([\s\S]*?)```/g, function(m, code) {
    codeBlocks.push('<pre><code>' + code.trim() + '</code></pre>');
    return '%%CODEBLOCK' + (codeBlocks.length - 1) + '%%';
  });

  var inlineCodes = [];
  html = html.replace(/`([^`]+)`/g, function(m, code) {
    inlineCodes.push('<code>' + code + '</code>');
    return '%%INLINECODE' + (inlineCodes.length - 1) + '%%';
  });

  function mathHTML(math, displayMode) {
    if (typeof katex !== 'undefined') {
      try { return katex.renderToString(math, { displayMode: displayMode, throwOnError: false }); } catch(e) {}
    }
    return '<span class="math-fallback">' + math.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</span>';
  }

  var displayMath = [];
  html = html.replace(/\$\$([\s\S]*?)\$\$/g, function(m, math) {
    displayMath.push('<div class="math-block">' + mathHTML(math.trim(), true) + '</div>');
    return '%%DISPLAYMATH' + (displayMath.length - 1) + '%%';
  });
  html = html.replace(/\\\[([\s\S]*?)\\\]/g, function(m, math) {
    displayMath.push('<div class="math-block">' + mathHTML(math.trim(), true) + '</div>');
    return '%%DISPLAYMATH' + (displayMath.length - 1) + '%%';
  });

  var inlineMath = [];
  html = html.replace(/\$([^$\n]+?)\$/g, function(m, math) {
    inlineMath.push(mathHTML(math.trim(), false));
    return '%%INLINEMATH' + (inlineMath.length - 1) + '%%';
  });
  html = html.replace(/\\\(([\s\S]*?)\\\)/g, function(m, math) {
    inlineMath.push(mathHTML(math.trim(), false));
    return '%%INLINEMATH' + (inlineMath.length - 1) + '%%';
  });

  var lines = html.split('\n');
  var result = [];
  var inList = false;
  var listType = null;
  var tableRows = [];

  function flushTable() {
    if (tableRows.length < 2) { tableRows = []; return; }
    result.push('<table>');
    var sepLine = tableRows[1].replace(/\s/g,'');
    if (/^\|[-:|]+\|?$/.test(sepLine)) {
      result.push('<thead><tr>');
      tableRows[0].split('|').filter(function(c){ return c.trim() !== ''; }).forEach(function(c){
        result.push('<th>' + applyInline(c.trim()) + '</th>');
      });
      result.push('</tr></thead><tbody>');
      for (var ti = 2; ti < tableRows.length; ti++) {
        result.push('<tr>');
        tableRows[ti].split('|').filter(function(c){ return c.trim() !== ''; }).forEach(function(c){
          result.push('<td>' + applyInline(c.trim()) + '</td>');
        });
        result.push('</tr>');
      }
      result.push('</tbody></table>');
    }
    tableRows = [];
  }

  for (var i = 0; i < lines.length; i++) {
    var line = lines[i];
    if (/^\|.+\|$/.test(line.trim())) {
      tableRows.push(line);
      continue;
    } else if (tableRows.length) {
      flushTable();
    }
    if (/^---+\s*$/.test(line)) {
      if (inList) { result.push(listType === 'ul' ? '</ul>' : '</ol>'); inList = false; listType = null; }
      result.push('<hr>');
      continue;
    }
    var hMatch = line.match(/^(#{1,3})\s+(.+)$/);
    if (hMatch) {
      if (inList) { result.push(listType === 'ul' ? '</ul>' : '</ol>'); inList = false; listType = null; }
      result.push('<h' + hMatch[1].length + '>' + applyInline(hMatch[2]) + '</h' + hMatch[1].length + '>');
      continue;
    }
    var bqMatch = line.match(/^>\s?(.*)$/);
    if (bqMatch) {
      if (inList) { result.push(listType === 'ul' ? '</ul>' : '</ol>'); inList = false; listType = null; }
      result.push('<blockquote>' + applyInline(bqMatch[1]) + '</blockquote>');
      continue;
    }
    var ulMatch = line.match(/^[\s]*[-*+]\s+(.+)$/);
    if (ulMatch) {
      if (!inList || listType !== 'ul') {
        if (inList) result.push('</ol>');
        result.push('<ul>');
        inList = true;
        listType = 'ul';
      }
      result.push('<li>' + applyInline(ulMatch[1]) + '</li>');
      continue;
    }
    var olMatch = line.match(/^[\s]*\d+\.\s+(.+)$/);
    if (olMatch) {
      if (!inList || listType !== 'ol') {
        if (inList) result.push('</ul>');
        result.push('<ol>');
        inList = true;
        listType = 'ol';
      }
      result.push('<li>' + applyInline(olMatch[1]) + '</li>');
      continue;
    }
    if (inList) { result.push(listType === 'ul' ? '</ul>' : '</ol>'); inList = false; listType = null; }
    if (line.trim()) {
      result.push('<p>' + applyInline(line.trim()) + '</p>');
    } else {
      result.push('<br>');
    }
  }

  if (tableRows.length) flushTable();
  if (inList) result.push(listType === 'ul' ? '</ul>' : '</ol>');

  html = result.join('\n');

  html = html.replace(/%%CODEBLOCK(\d+)%%/g, function(m, idx) { return codeBlocks[parseInt(idx)] || ''; });
  html = html.replace(/%%INLINECODE(\d+)%%/g, function(m, idx) { return inlineCodes[parseInt(idx)] || ''; });
  html = html.replace(/%%DISPLAYMATH(\d+)%%/g, function(m, idx) { return displayMath[parseInt(idx)] || ''; });
  html = html.replace(/%%INLINEMATH(\d+)%%/g, function(m, idx) { return inlineMath[parseInt(idx)] || ''; });

  return html;

  function applyInline(t) {
    t = t.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
    t = t.replace(/\*([^*]+)\*/g, '<em>$1</em>');
    t = t.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank" rel="noopener">$1</a>');
    return t;
  }
}

/* ---- Stop generation ---- */
function stopGeneration() {
  if (generationAbort) {
    generationAbort.abort();
    generationAbort = null;
  }
  isGenerating = false;
  var stopBtn = document.getElementById('stop-generation-btn');
  if (stopBtn) stopBtn.style.display = 'none';
  var streamingEl = document.getElementById('streaming-msg');
  if (streamingEl && !streamingEl.dataset.complete) {
    var partialText = streamingEl.dataset.partialText || '';
    if (partialText) {
      var d3 = msgDir(partialText); streamingEl.dir = d3; streamingEl.style.textAlign = d3 === 'rtl' ? 'right' : 'left'; streamingEl.style.direction = d3; streamingEl.style.unicodeBidi = 'isolate';
      streamingEl.innerHTML = renderMarkdown(partialText) + botMsgActions();
      streamingEl.id = '';
      chatHistory.push({ role: 'assistant', content: partialText, timestamp: Date.now() });
      saveCurrentConversation();
    } else {
      streamingEl.remove();
    }
  }
}

function createStopBtn() {
  var existing = document.getElementById('stop-generation-btn');
  if (existing) return existing;
  var btn = document.createElement('button');
  btn.id = 'stop-generation-btn';
  btn.className = 'btn btn-danger btn-sm';
  btn.innerHTML = icon('stop') + ' ' + (t('assistant.stop') || 'Stop');
  btn.style.display = 'none';
  btn.onclick = stopGeneration;
  var tools = document.querySelector('.chat-input-tools');
  if (tools) tools.insertBefore(btn, tools.firstChild);
  return btn;
}

/* ---- Regenerate last ---- */
function regenerateLast() {
  if (isGenerating) return;
  var lastUserIdx = -1;
  for (var ri = chatHistory.length - 1; ri >= 0; ri--) {
    if (chatHistory[ri].role === 'user') { lastUserIdx = ri; break; }
  }
  if (lastUserIdx < 0) return;
  var lastUserMsg = chatHistory[lastUserIdx];
  chatHistory = chatHistory.slice(0, lastUserIdx + 1);
  renderChatHistory();
  sendMessage(lastUserMsg.content, lastUserMsg.fileName ? lastUserMsg : null);
}

/* ---- Suggested questions ---- */
function generateSuggestions(userText, reply) {
  var suggestionsEl = document.getElementById('suggestion-chips');
  if (!suggestionsEl) return;
  var key = getSelectedKey();
  if (!key) return;
  var prompt = 'Basé sur cette conversation, génère 3 questions courtes (1 ligne chacune, séparées par "||") que l\'utilisateur pourrait poser.\n\nMessage: ' + userText.slice(0, 200) + '\nRéponse: ' + reply.slice(0, 300);
  callProvider(key, [{ role: 'user', content: prompt }]).then(function(sugReply) {
    var questions = sugReply.split('||').map(function(s) { return s.trim(); }).filter(function(s) { return s.length > 5; }).slice(0, 3);
    if (!questions.length) return;
    suggestionsEl.innerHTML = questions.map(function(q) {
      return '<button type="button" class="chip" data-prompt="' + q.replace(/"/g,'&quot;') + '">' + q.replace(/[&<>"']/g, function(m){ return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]; }) + '</button>';
    }).join('');
    suggestionsEl.style.display = 'flex';
    suggestionsEl.querySelectorAll('.chip').forEach(function(chip) {
      chip.addEventListener('click', function() {
        var ta = document.getElementById('chat-textarea');
        if (ta) {
          ta.value = chip.dataset.prompt || chip.textContent;
          ta.style.height = 'auto';
          ta.style.height = Math.min(ta.scrollHeight, 140) + 'px';
          ta.focus();
        }
      });
    });
  }).catch(function() {}); // non-critical
}

function wireAssistantEvents() {
  const form = document.getElementById('chat-form');
  const textarea = document.getElementById('chat-textarea');
  const clearBtn = document.getElementById('chat-clear-btn');
  const fileInput = document.getElementById('chat-file-input');

  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    if (isGenerating) return;
    const text = textarea.value.trim();
    if (!text && !attachedFile) return;
    textarea.value = '';
    textarea.style.height = 'auto';
    await sendMessage(text, attachedFile);
    attachedFile = null;
    document.getElementById('chat-attachments').innerHTML = '';
  });

  textarea.addEventListener('keydown', (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      form.requestSubmit();
    }
  });

  textarea.addEventListener('input', () => {
    textarea.style.height = 'auto';
    textarea.style.height = Math.min(textarea.scrollHeight, 140) + 'px';
  });

  clearBtn.addEventListener('click', () => {
    if (isGenerating) { stopGeneration(); }
    chatHistory = [];
    attachedFile = null;
    document.getElementById('chat-attachments').innerHTML = '';
    renderChatHistory();
    saveCurrentConversation();
  });

  const imgBtn = document.getElementById('chat-img-btn');
  if (imgBtn) {
    imgBtn.addEventListener('click', () => {
      if (isGenerating) return;
      var txt = document.getElementById('chat-textarea').value.trim();
      if (txt) { document.getElementById('chat-textarea').value = ''; doImg(txt); return; }
      var scrollEl = document.getElementById('chat-scroll');
      if (!scrollEl) { var p = window.prompt('Décris l\'image à créer…'); if (p) doImg(p.trim()); return; }
      var row = document.createElement('div');
      row.style.cssText = 'display:flex;gap:var(--space-1);padding:var(--space-2)0;background:var(--cream-card);border-radius:var(--radius-md);padding:var(--space-2)var(--space-3);margin-bottom:var(--space-1);';
      row.innerHTML = '<input type="text" id="pg-img-inp" placeholder="Décris l\'image à créer…" style="flex:1;padding:var(--space-2)var(--space-3);border:2px solid var(--kraft);border-radius:var(--radius-md);font-size:var(--fs-xs);background:var(--surface);color:var(--ink);">' +
        '<button class="btn btn-primary btn-sm" id="pg-img-go">OK</button>' +
        '<button class="btn btn-ghost btn-sm" id="pg-img-cancel">Annuler</button>';
      scrollEl.appendChild(row);
      scrollEl.scrollTop = scrollEl.scrollHeight;
      document.getElementById('pg-img-inp').focus();
      document.getElementById('pg-img-go').onclick = function() { var v = document.getElementById('pg-img-inp').value.trim(); row.remove(); if (v) doImg(v); };
      document.getElementById('pg-img-cancel').onclick = function() { row.remove(); };
      document.getElementById('pg-img-inp').onkeydown = function(e) { if (e.key === 'Enter') document.getElementById('pg-img-go').click(); };
    });
  }

  async function doImg(prompt) {
    chatHistory.push({ role: 'user', content: '🎨 Générer une image: ' + prompt, timestamp: Date.now() });
    renderChatHistory();
    var active = getSelectedKey();
    if (!active) {
      chatHistory.push({ role: 'assistant', content: '⚠️ Aucune clé API configurée.' });
      renderChatHistory(); return;
    }
    document.getElementById('chat-empty').classList.add('hidden');
    chatHistory.push({ role: 'assistant', content: '⏳ Génération…' });
    renderChatHistory();
    var scrollEl = document.getElementById('chat-scroll');
    if (scrollEl) scrollEl.scrollTop = scrollEl.scrollHeight;
    try {
      var imgUrl = await generateImage(prompt, active);
      chatHistory.pop();
      chatHistory.push({ role: 'assistant', content: '', imgUrl: imgUrl, timestamp: Date.now() });
    } catch (err) {
      chatHistory.pop();
      chatHistory.push({ role: 'assistant', content: '⚠️ ' + err.message });
    }
    renderChatHistory();
    saveCurrentConversation();
  }

  var canvasBtn = document.getElementById('chat-canvas-btn');
  if (canvasBtn) {
    canvasBtn.addEventListener('click', function() {
      if (isGenerating) return;
      try {
        openWhiteboard(function(data, isImage) {
          if (!data) return;
          chatHistory.push({ role: 'user', content: '🎨 Canvas: ' + (document.getElementById('wb-prompt')?.value?.trim() || 'Création'), timestamp: Date.now() });
          if (isImage) {
            chatHistory.push({ role: 'assistant', content: '', imgUrl: data, timestamp: Date.now() });
          } else {
            chatHistory.push({ role: 'assistant', content: data, timestamp: Date.now() });
          }
          renderChatHistory();
          var scrollEl = document.getElementById('chat-scroll');
          if (scrollEl) scrollEl.scrollTop = scrollEl.scrollHeight;
          saveCurrentConversation();
        });
      } catch(e) {
        console.error('[Canvas]', e);
        showToast('Erreur Canvas: ' + e.message);
      }
    });
  }

  fileInput.addEventListener('change', () => {
    const file = fileInput.files[0];
    if (!file) return;
    attachedFile = file;
    const attachEl = document.getElementById('chat-attachments');
    attachEl.innerHTML = `<span class="file-tag">${icon('paperclip')} ${escapeHTML(file.name)} <button type="button" class="file-remove" id="file-remove-btn">${icon('close')}</button></span>`;
    document.getElementById('file-remove-btn').onclick = () => {
      attachedFile = null;
      fileInput.value = '';
      attachEl.innerHTML = '';
    };
    fileInput.value = '';
  });

  document.querySelectorAll('.chip').forEach(chip => {
    chip.addEventListener('click', () => {
      textarea.value = chip.dataset.prompt || chip.textContent;
      sendMessage(textarea.value, attachedFile);
      textarea.value = '';
      attachedFile = null;
      document.getElementById('chat-attachments').innerHTML = '';
    });
  });

  // Keyboard shortcuts
  document.addEventListener('keydown', function(e) {
    if (e.key === '/' && !e.ctrlKey && !e.metaKey && document.activeElement?.tagName !== 'INPUT' && document.activeElement?.tagName !== 'TEXTAREA') {
      var docModal = document.getElementById('doc-modal');
      if (docModal && docModal.classList.contains('open')) return;
      var searchInput = document.getElementById('chat-search-inp');
      if (searchInput) {
        if (searchInput.style.display === 'none') searchInput.style.display = '';
        searchInput.focus();
        e.preventDefault();
      }
    }
    if (e.key === 'Escape') {
      var conv = document.getElementById('conv-sidebar');
      if (conv && conv.style.display !== 'none') conv.style.display = 'none';
      var prompts = document.getElementById('saved-prompts-panel');
      if (prompts && prompts.style.display !== 'none') prompts.style.display = 'none';
    }
  });
}

function wireToolbarEvents() {
  const convToggle = document.getElementById('conv-toggle-btn');
  const convSidebar = document.getElementById('conv-sidebar');
  if (convToggle && convSidebar) {
    convToggle.onclick = () => { convSidebar.style.display = convSidebar.style.display === 'none' ? 'block' : 'none'; };
  }
  const newBtn = document.getElementById('conv-new-btn');
  if (newBtn) newBtn.onclick = () => { newConversation(); document.getElementById('conv-sidebar').style.display = 'none'; };

  const promptsBtn = document.getElementById('saved-prompts-btn');
  const promptsPanel = document.getElementById('saved-prompts-panel');
  if (promptsBtn && promptsPanel) {
    promptsBtn.onclick = () => { promptsPanel.style.display = promptsPanel.style.display === 'none' ? 'block' : 'none'; };
  }
  document.getElementById('close-prompts-btn').onclick = () => { promptsPanel.style.display = 'none'; };

  const exportBtn = document.getElementById('export-chat-btn');
  if (exportBtn) {
    exportBtn.onclick = (e) => {
      if (!chatHistory.length) { showToast('Rien à exporter.'); return; }
      showExportMenu(e.target || e.currentTarget, function(fmt) { exportChat(fmt); });
    };
  }

  const toggleSearch = document.getElementById('toggle-search-btn');
  const searchInp = document.getElementById('chat-search-inp');
  if (toggleSearch && searchInp) {
    toggleSearch.onclick = () => {
      searchInp.style.display = searchInp.style.display === 'none' ? '' : 'none';
      if (searchInp.style.display === 'none') { searchInp.value = ''; showFilteredChat = false; renderChatHistory(); }
      else searchInp.focus();
    };
    searchInp.oninput = () => {
      renderFilteredChat(searchInp.value.trim());
    };
  }

  const ta = document.getElementById('chat-textarea');
  if (ta && promptsPanel) {
    var oldBtn = document.getElementById('save-prompt-quick-btn');
    if (!oldBtn) {
      var btn = document.createElement('button');
      btn.id = 'save-prompt-quick-btn';
      btn.className = 'btn btn-ghost btn-sm';
      btn.textContent = '💾';
      btn.title = 'Sauvegarder le prompt actuel';
      btn.style.marginInlineStart = 'auto';
      btn.onclick = function() {
        var txt = ta.value.trim();
        if (!txt) { showToast('Le champ est vide.'); return; }
        var title = prompt('Nom du prompt :', txt.slice(0, 40));
        if (title) { addSavedPrompt(title.trim(), txt); showToast('Prompt sauvegardé !'); }
      };
      document.querySelector('.chat-input-tools')?.appendChild(btn);
    }
  }
}

async function sendMessage(text, file) {
  if (isGenerating) return;
  const active = getSelectedKey();
  const scrollEl = document.getElementById('chat-scroll');
  const suggestionEl = document.getElementById('suggestion-chips');
  if (suggestionEl) { suggestionEl.innerHTML = ''; suggestionEl.style.display = 'none'; }

  let userContent = text;
  if (file) {
    const fileData = await readFileAsBase64(file);
    userContent = `[Fichier joint: ${file.name}]\n\n${text}`;
    chatHistory.push({ role: 'user', content: userContent, fileName: file.name, fileData, fileType: file.type, timestamp: Date.now() });
  } else {
    chatHistory.push({ role: 'user', content: userContent, timestamp: Date.now() });
  }
  renderChatHistory();

  if (!active) {
    chatHistory.push({ role: 'assistant', content: t('assistant.noProvider') });
    renderChatHistory();
    return;
  }

  document.getElementById('chat-empty').classList.add('hidden');

  var stopBtn = document.getElementById('stop-generation-btn');
  if (stopBtn) stopBtn.style.display = 'inline-flex';

  var msgEl = document.createElement('div');
  msgEl.className = 'chat-msg bot';
  msgEl.id = 'streaming-msg';
  scrollEl.appendChild(msgEl);
  scrollEl.scrollTop = scrollEl.scrollHeight;

  generationAbort = new AbortController();
  isGenerating = true;

  try {
    var reply = await callProvider(active, chatHistory, null, generationAbort.signal);
    isGenerating = false;
    if (stopBtn) stopBtn.style.display = 'none';

    var words = reply.split(/\s+/);
    if (words.length <= 2) {
      msgEl.innerHTML = renderMarkdown(reply) + botMsgActions();
      var d = msgDir(reply); msgEl.dir = d; msgEl.style.textAlign = d === 'rtl' ? 'right' : 'left'; msgEl.style.direction = d; msgEl.style.unicodeBidi = 'isolate';
      msgEl.id = '';
      chatHistory.push({ role: 'assistant', content: reply, timestamp: Date.now() });
      saveCurrentConversation();
      generateSuggestions(text, reply);
      return;
    }

    var wordIdx = 1;
    var speed = Math.max(10, Math.min(50, 2000 / words.length));
    var partialText = '';

    function revealWord() {
      if (!document.getElementById('streaming-msg')) return;
      partialText = words.slice(0, wordIdx).join(' ');
      var d3 = msgDir(partialText); msgEl.dir = d3; msgEl.style.textAlign = d3 === 'rtl' ? 'right' : 'left'; msgEl.style.direction = d3; msgEl.style.unicodeBidi = 'isolate';
      msgEl.innerHTML = renderMarkdown(partialText);
      msgEl.dataset.partialText = partialText;
      scrollEl.scrollTop = scrollEl.scrollHeight;
      wordIdx++;
      if (wordIdx <= words.length) {
        setTimeout(revealWord, speed);
      } else {
        msgEl.innerHTML = renderMarkdown(reply) + botMsgActions();
        var d2 = msgDir(reply); msgEl.dir = d2; msgEl.style.textAlign = d2 === 'rtl' ? 'right' : 'left'; msgEl.style.direction = d2; msgEl.style.unicodeBidi = 'isolate';
        msgEl.id = '';
        delete msgEl.dataset.partialText;
        msgEl.dataset.complete = '1';
        chatHistory.push({ role: 'assistant', content: reply, timestamp: Date.now() });
        saveCurrentConversation();
        generateSuggestions(text, reply);
      }
    }
    revealWord();
  } catch (err) {
    isGenerating = false;
    if (stopBtn) stopBtn.style.display = 'none';

    if (err.name === 'AbortError') {
      // already handled by stopGeneration()
      return;
    }
    console.error(err);
    document.getElementById('streaming-msg')?.remove();
    let msg = t('assistant.error') + ' (' + err.message + ')';
    if (/401/.test(err.message)) {
      msg += '\n\n' + t('assistant.hint401');
    } else if (/404/.test(err.message)) {
      msg += '\n\n' + t('assistant.hint404');
    } else if (/429/.test(err.message)) {
      msg += '\n\n' + t('assistant.hint429');
    } else if (/image/i.test(err.message) && /not support/i.test(err.message)) {
      msg += '\n\n💡 Ce modèle ne supporte pas les images. Essaie sans fichier joint, ou change de modèle (ex: GPT-4o, Claude Sonnet, Gemini).';
    }
    chatHistory.push({ role: 'assistant', content: msg });
    renderChatHistory();
    saveCurrentConversation();
  }
}

function readFileAsBase64(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

/* ---- Shared Canvas ---- */
function openWhiteboard(onResult) {
  var existing = document.getElementById('wb-overlay');
  if (existing) { existing.remove(); return; }
  var overlay = document.createElement('div');
  overlay.id = 'wb-overlay';
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:2000;display:flex;align-items:center;justify-content:center;';
  overlay.onclick = function(e) { if (e.target === overlay) overlay.remove(); };

  var box = document.createElement('div');
  box.style.cssText = 'background:var(--surface);border-radius:var(--radius-lg);padding:var(--space-4);max-width:600px;width:90%;';
  box.innerHTML =
    '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:var(--space-3);">' +
      '<strong style="font-size:var(--fs-md);">Canvas — Création par IA</strong>' +
      '<button class="btn btn-ghost btn-sm" id="wb-close">' + icon('close') + '</button>' +
    '</div>' +
    '<p style="font-size:var(--fs-sm);color:var(--ink-soft);margin-bottom:var(--space-3);">Décris ce que tu veux créer (image, exercice, résumé, tableau, schéma…). L\'IA générera le contenu.</p>' +
    '<textarea id="wb-prompt" rows="4" style="width:100%;padding:var(--space-3);border:2px solid var(--kraft);border-radius:var(--radius-md);background:var(--surface);color:var(--ink);font-family:inherit;font-size:var(--fs-sm);resize:vertical;box-sizing:border-box;" placeholder="Ex: Génère un tableau récapitulatif des verbes du 1er groupe au présent"></textarea>' +
    '<div style="display:flex;gap:var(--space-2);margin-top:var(--space-3);align-items:center;flex-wrap:wrap;">' +
      '<button class="btn btn-primary btn-sm" id="wb-generate">' + icon('send') + ' Générer</button>' +
      '<select id="wb-type" style="padding:var(--space-2)var(--space-3);border:2px solid var(--kraft);border-radius:var(--radius-md);font-size:var(--fs-xs);background:var(--surface);color:var(--ink);">' +
        '<option value="auto">Auto (laisser l\'IA décider)</option>' +
        '<option value="image">Image</option>' +
        '<option value="text">Texte / Exercice</option>' +
        '<option value="table">Tableau</option>' +
        '<option value="code">Code / Formule</option>' +
      '</select>' +
    '</div>' +
    '<div id="wb-result" style="margin-top:var(--space-3);padding:var(--space-3);background:var(--cream-card);border:var(--border-w)solid var(--kraft-line);border-radius:var(--radius-md);font-size:var(--fs-sm);line-height:1.55;max-height:400px;overflow-y:auto;display:none;white-space:pre-wrap;"></div>' +
    '<div style="display:flex;gap:var(--space-2);margin-top:var(--space-3);flex-wrap:wrap;">' +
      '<button class="btn btn-primary btn-sm" id="wb-send" style="display:none;">Ajouter au chat</button>' +
      '<button class="btn btn-secondary btn-sm" id="wb-retry" style="display:none;">Régénérer</button>' +
    '</div>';

  overlay.appendChild(box);
  document.body.appendChild(overlay);

  var lastResult = null;
  var resultIsImage = false;

  document.getElementById('wb-close').onclick = function() { overlay.remove(); };
  async function doGenerate() {
    var prompt = document.getElementById('wb-prompt').value.trim();
    if (!prompt) return;
    var type = document.getElementById('wb-type').value;
    var resultDiv = document.getElementById('wb-result');
    var sendBtn = document.getElementById('wb-send');
    var retryBtn = document.getElementById('wb-retry');
    resultDiv.style.display = 'block';
    resultDiv.textContent = '⏳ Génération en cours…';
    sendBtn.style.display = 'none';
    retryBtn.style.display = 'none';
    lastResult = null;
    resultIsImage = false;

    var key = typeof getSelectedKey === 'function' ? getSelectedKey() : null;
    if (!key) {
      resultDiv.textContent = '⚠️ Aucune clé API configurée.';
      return;
    }

    try {
      var provName = key.label || key.provider || '?';
      var systemMsg = 'Tu es un assistant de création de contenu pédagogique algérien. ' +
        'Génère le contenu demandé de manière claire, structurée et adaptée au programme algérien.';
      if (type === 'image') {
        var imgUrl = await generateImage(prompt, key);
        lastResult = imgUrl;
        resultIsImage = true;
        resultDiv.innerHTML = '<img src="' + escapeAttr(imgUrl) + '" alt="' + escapeAttr(prompt) + '" style="max-width:100%;border-radius:var(--radius-md);">';
        sendBtn.style.display = 'inline-flex';
        retryBtn.style.display = 'inline-flex';
        return;
      }
      var fullPrompt = 'Type demandé: ' + type + '\n\nConsigne: ' + prompt;
      var reply = await callProvider(key, [{ role: 'user', content: fullPrompt }], systemMsg);
      lastResult = reply;
      resultIsImage = false;
      resultDiv.textContent = reply;
      sendBtn.style.display = 'inline-flex';
      retryBtn.style.display = 'inline-flex';
    } catch (err) {
      resultDiv.textContent = '⚠️ ' + err.message;
      retryBtn.style.display = 'inline-flex';
    }
  };

  document.getElementById('wb-generate').onclick = doGenerate;
  document.getElementById('wb-retry').onclick = doGenerate;

  document.getElementById('wb-send').onclick = function() {
    if (lastResult) {
      if (onResult) onResult(lastResult, resultIsImage);
    }
    overlay.remove();
  };

  document.getElementById('wb-prompt').onkeydown = function(e) {
    if (e.key === 'Enter' && e.shiftKey) {
      e.preventDefault();
      document.getElementById('wb-generate').click();
    }
  };
}

/* ---- Shared Image Generation ---- */
async function generateImage(prompt, keyConfig) {
  if (!keyConfig) throw new Error('Aucune clé API configurée.');
  var apiKey = (typeof sanitizeApiKey === 'function') ? sanitizeApiKey(keyConfig.apiKey) : keyConfig.apiKey.trim();
  var provLabel = keyConfig.label || keyConfig.provider || '?';

  if (keyConfig.provider === 'openai') {
    var res = await fetch('https://api.openai.com/v1/images/generations', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + apiKey },
      body: JSON.stringify({ model: 'dall-e-3', prompt: prompt, n: 1, size: '1024x1024' })
    });
    if (!res.ok) {
      var errData;
      try { errData = await res.json(); } catch(e) {}
      throw new Error((errData && errData.error && errData.error.message) || 'HTTP ' + res.status);
    }
    var data = await res.json();
    return data.data && data.data[0] && data.data[0].url;

  } else if (keyConfig.provider === 'google') {
    var res = await fetch('https://generativelanguage.googleapis.com/v1beta/models/imagen-3.0-generate-001:predict?key=' + apiKey, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ instances: [{ prompt: prompt }], parameters: { sampleCount: 1 } })
    });
    if (!res.ok) {
      var errData;
      try { errData = await res.json(); } catch(e) {}
      throw new Error((errData && errData.error && errData.error.message) || 'HTTP ' + res.status);
    }
    var data = await res.json();
    if (data.predictions && data.predictions[0] && data.predictions[0].bytesBase64Encoded) {
      return 'data:image/png;base64,' + data.predictions[0].bytesBase64Encoded;
    }
    throw new Error('Format de réponse Imagen inattendu.');

  } else {
    throw new Error('La génération d\'images nécessite une clé OpenAI (DALL·E) ou Google (Imagen). Clé actuelle: ' + provLabel);
  }
}

async function extractApiError(res) {
  let detail = '';
  try {
    const data = await res.json();
    detail = data?.error?.message || data?.error?.type || JSON.stringify(data).slice(0, 200);
  } catch {
    try { detail = (await res.text()).slice(0, 200); } catch { /* ignore */ }
  }
  return `HTTP ${res.status}${detail ? ' — ' + detail : ''}`;
}

async function callProvider(keyConfig, history, systemOverride, signal) {
  const systemPrompt = systemOverride || getSystemPrompt();
  const apiKey = (typeof sanitizeApiKey === 'function')
    ? sanitizeApiKey(keyConfig.apiKey || '')
    : (keyConfig.apiKey || '').trim();

  if (keyConfig.provider === 'anthropic') {
    const messages = history.map(m => {
      if (m.fileData && m.fileType?.startsWith('image/')) {
        return {
          role: m.role,
          content: [
            { type: 'image', source: { type: 'base64', media_type: m.fileType, data: m.fileData.split(',')[1] } },
            { type: 'text', text: m.content }
          ]
        };
      }
      return { role: m.role, content: m.content };
    });
    const res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': apiKey,
        'anthropic-version': '2023-06-01',
        'anthropic-dangerous-direct-browser-access': 'true'
      },
      signal: signal,
      body: JSON.stringify({
        model: keyConfig.model,
        max_tokens: 1500,
        system: systemPrompt,
        messages
      })
    });
    if (!res.ok) throw new Error(await extractApiError(res));
    const data = await res.json();
    return (data.content || []).filter(b => b.type === 'text').map(b => b.text).join('\n') || '…';
  }

  if (keyConfig.provider === 'openai') {
    const messages = [{ role: 'system', content: systemPrompt }];
    history.forEach(m => {
      if (m.fileData && m.fileType?.startsWith('image/')) {
        messages.push({
          role: m.role,
          content: [
            { type: 'text', text: m.content },
            { type: 'image_url', image_url: { url: m.fileData } }
          ]
        });
      } else {
        messages.push({ role: m.role, content: m.content });
      }
    });
    const res = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer ' + apiKey
      },
      signal: signal,
      body: JSON.stringify({
        model: keyConfig.model,
        messages,
        max_tokens: 1500
      })
    });
    if (!res.ok) throw new Error(await extractApiError(res));
    const data = await res.json();
    return data.choices?.[0]?.message?.content || '…';
  }

  if (keyConfig.provider === 'google') {
    const contents = history.map(m => {
      const parts = [{ text: m.content }];
      if (m.fileData && m.fileType?.startsWith('image/')) {
        parts.unshift({ inlineData: { mimeType: m.fileType, data: m.fileData.split(',')[1] } });
      }
      return { role: m.role === 'assistant' ? 'model' : 'user', parts };
    });
    const url = `https://generativelanguage.googleapis.com/v1beta/models/${keyConfig.model}:generateContent?key=${apiKey}`;
    const res = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      signal: signal,
      body: JSON.stringify({
        systemInstruction: { parts: [{ text: systemPrompt }] },
        contents
      })
    });
    if (!res.ok) throw new Error(await extractApiError(res));
    const data = await res.json();
    return data.candidates?.[0]?.content?.parts?.map(p => p.text).join('\n') || '…';
  }

  if (keyConfig.provider === 'custom') {
    const endpoint = keyConfig.endpoint || '';
    if (!endpoint) throw new Error('Endpoint manquant pour le fournisseur personnalisé');
    const messages = [{ role: 'system', content: systemPrompt }, ...history.map(m => ({ role: m.role, content: m.content }))];
    const res = await fetch(endpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer ' + apiKey
      },
      signal: signal,
      body: JSON.stringify({
        model: keyConfig.model,
        messages,
        max_tokens: 1500
      })
    });
    if (!res.ok) throw new Error(await extractApiError(res));
    const data = await res.json();
    return data.choices?.[0]?.message?.content || '…';
  }

  throw new Error('Unknown provider');
}

/* ---- Copy to clipboard ---- */
function copyMsgContent(btn) {
  var msgEl = btn.closest('.chat-msg');
  if (!msgEl) return;
  var clone = msgEl.cloneNode(true);
  clone.querySelectorAll('.copy-btn, .regenerate-btn, .file-tag').forEach(function(el) { el.remove(); });
  var text = clone.textContent.trim();
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(text).then(function() {
      var span = btn.querySelector('span');
      if (span) span.textContent = '✓';
      btn.classList.add('copied');
      setTimeout(function() {
        if (span) span.textContent = t('assistant.copy') || 'Copier';
        btn.classList.remove('copied');
      }, 2000);
    }).catch(function() { fallbackCopy(text, btn); });
  } else {
    fallbackCopy(text, btn);
  }
}
function fallbackCopy(text, btn) {
  var ta = document.createElement('textarea');
  ta.value = text;
  ta.style.position = 'fixed'; ta.style.opacity = '0';
  document.body.appendChild(ta);
  ta.select();
  try { document.execCommand('copy'); } catch(e) {}
  document.body.removeChild(ta);
  var span = btn.querySelector('span');
  if (span) span.textContent = '✓';
  btn.classList.add('copied');
  setTimeout(function() {
    if (span) span.textContent = t('assistant.copy') || 'Copier';
    btn.classList.remove('copied');
  }, 2000);
}
/* ============================================================
   ADMIN DOCUMENT MANAGER — add / edit / delete documents
   Strategy: db.json is static (read-only on disk from the browser).
   Local additions/edits/deletions are stored in localStorage and
   MERGED with db.json at runtime everywhere documents are shown.
   The admin can export an updated db.json to make changes permanent
   for all visitors (replace the file in data/).
   ============================================================ */

const LOCAL_DOCS_KEY = 'inry_local_docs';       // array of added/edited docs (full objects)
const DELETED_DOCS_KEY = 'inry_deleted_doc_ids'; // array of ids to hide from original db.json
const PENDING_DOCS_KEY = 'inry_pending_docs';    // array of imported docs awaiting validation
const HIDDEN_DOCS_KEY = 'inry_hidden_doc_ids';    // array of doc ids hidden from public view

function getHiddenIds() {
  try { return JSON.parse(localStorage.getItem(HIDDEN_DOCS_KEY) || '[]'); }
  catch { return []; }
}
function saveHiddenIds(ids) {
  localStorage.setItem(HIDDEN_DOCS_KEY, JSON.stringify(ids));
}

/* ---- HIDE / UNHIDE for structure entities ---- */
var ENTITY_HIDDEN_KEYS = {
  levels: 'inry_hidden_level_ids',
  streams: 'inry_hidden_stream_ids',
  subjects: 'inry_hidden_subject_ids',
  documentTypes: 'inry_hidden_doc_type_ids'
};

function getEntityHiddenIds(type) {
  var key = ENTITY_HIDDEN_KEYS[type];
  if (!key) return [];
  try { return JSON.parse(localStorage.getItem(key) || '[]'); } catch { return []; }
}

function saveEntityHiddenIds(type, ids) {
  var key = ENTITY_HIDDEN_KEYS[type];
  if (!key) return;
  localStorage.setItem(key, JSON.stringify(ids));
}

function getLocalDocs() {
  try { return JSON.parse(localStorage.getItem(LOCAL_DOCS_KEY) || '[]'); }
  catch { return []; }
}
function saveLocalDocs(docs) {
  localStorage.setItem(LOCAL_DOCS_KEY, JSON.stringify(docs));
}
function getDeletedIds() {
  try { return JSON.parse(localStorage.getItem(DELETED_DOCS_KEY) || '[]'); }
  catch { return []; }
}
function saveDeletedIds(ids) {
  localStorage.setItem(DELETED_DOCS_KEY, JSON.stringify(ids));
}

/**
 * Returns the effective document list = original db.json documents
 * (minus deleted ones) + local docs (added or edited), local edits
 * taking priority over originals with the same id.
 * Call this once after loadData() and it patches APP.db.documents in place
 * so the rest of the app (home, library, modal) needs no changes.
 */
function applyLocalDocOverrides() {
  if (!APP.db || !APP.db.documents) return;
  const deleted = new Set(getDeletedIds());
  const localDocs = getLocalDocs();
  const localIds = new Set(localDocs.map(d => d.id));

  const base = APP.db.documents.filter(d => !deleted.has(d.id) && !localIds.has(d.id));
  APP.db.documents = [...base, ...localDocs.filter(d => !deleted.has(d.id))];
}

function upsertLocalDoc(doc) {
  const docs = getLocalDocs();
  const idx = docs.findIndex(d => d.id === doc.id);
  if (idx >= 0) docs[idx] = doc;
  else docs.push(doc);
  saveLocalDocs(docs);

  // if this id was previously marked deleted, un-delete it
  const deleted = getDeletedIds().filter(id => id !== doc.id);
  saveDeletedIds(deleted);
  scheduleAutoPush();
}

function deleteDocEverywhere(id) {
  // remove from local docs if present
  saveLocalDocs(getLocalDocs().filter(d => d.id !== id));
  // mark as deleted so it's hidden even if it exists in original db.json
  const deleted = getDeletedIds();
  if (!deleted.includes(id)) {
    deleted.push(id);
    saveDeletedIds(deleted);
  }
  scheduleAutoPush();
}

/* ---- GitHub Sync ---- */
var GH_CONFIG_KEY = 'inry_github_sync';
var GH_AUTO_PUSH_KEY = 'inry_github_auto_push';

function getGithubConfig() {
  try {
    var raw = localStorage.getItem(GH_CONFIG_KEY);
    return raw ? JSON.parse(raw) : { pat: '', repo: 'droidapk1002-beep/school-biblio-assets', branch: 'main', path: 'repo/data/db.json' };
  } catch { return { pat: '', repo: 'droidapk1002-beep/school-biblio-assets', branch: 'main', path: 'repo/data/db.json' }; }
}

function saveGithubConfig(cfg) {
  try { localStorage.setItem(GH_CONFIG_KEY, JSON.stringify(cfg)); } catch {}
}

function getGithubAutoPush() {
  return localStorage.getItem(GH_AUTO_PUSH_KEY) === 'true';
}

function setGithubAutoPush(val) {
  try { localStorage.setItem(GH_AUTO_PUSH_KEY, val ? 'true' : 'false'); } catch {}
}

function githubLog(msg, isError) {
  var el = document.getElementById('github-push-log');
  var status = document.getElementById('github-push-status');
  if (el) {
    el.style.display = 'block';
    var line = document.createElement('div');
    line.style.color = isError ? 'var(--red-stamp)' : 'var(--ink-soft)';
    line.style.marginBottom = '2px';
    line.textContent = '[' + new Date().toLocaleTimeString() + '] ' + msg;
    el.appendChild(line);
    el.scrollTop = el.scrollHeight;
  }
  if (status) {
    status.textContent = isError ? '❌ ' + msg : '✅ ' + msg;
    status.style.color = isError ? 'var(--red-stamp)' : 'var(--green)';
  }
}

async function pushDbToGithub() {
  var cfg = getGithubConfig();
  if (!cfg.pat) { showToast('Token GitHub manquant'); githubLog('Token GitHub manquant', true); return; }
  if (!cfg.repo || !cfg.branch || !cfg.path) { showToast('Config GitHub incomplète'); githubLog('Config GitHub incomplète', true); return; }

  var statusEl = document.getElementById('github-push-status');
  if (statusEl) { statusEl.textContent = '⏳ Push en cours…'; statusEl.style.color = 'var(--ink-soft)'; }
  githubLog('Préparation du push…');

  try {
    applyLocalDocOverrides();
    var exportObj = buildExportObj();
    var content = JSON.stringify(exportObj, null, 2);
    var encodedContent = btoa(unescape(encodeURIComponent(content)));

    var apiUrl = 'https://api.github.com/repos/' + cfg.repo + '/contents/' + cfg.path;
    var headers = { 'Authorization': 'token ' + cfg.pat, 'Accept': 'application/vnd.github.v3+json' };

    var existingSha = null;
    var getRes = await fetch(apiUrl + '?ref=' + cfg.branch, { headers: headers });
    if (getRes.ok) {
      var existing = await getRes.json();
      existingSha = existing.sha;
      githubLog('Fichier existant trouvé, SHA: ' + existingSha.substring(0, 8));
    } else if (getRes.status === 404) {
      githubLog('Fichier inexistant, création…');
    } else {
      var errText = await getRes.text();
      githubLog('Erreur lecture: ' + getRes.status + ' ' + errText, true);
      showToast('Erreur lecture GitHub');
      return;
    }

    var body = { message: 'chore(db): update db.json via inry admin [' + new Date().toISOString().slice(0, 19) + ']', content: encodedContent, branch: cfg.branch };
    if (existingSha) body.sha = existingSha;

    var putRes = await fetch(apiUrl, { method: 'PUT', headers: headers, body: JSON.stringify(body) });
    if (putRes.ok) {
      var result = await putRes.json();
      githubLog('Push réussi ! Commit: ' + (result.commit?.sha || '').substring(0, 8));
      showToast('db.json poussé sur GitHub ✓');
      saveDbBackup('github-push', exportObj);
      renderDbBackupList();
    } else {
      var errBody = await putRes.text();
      githubLog('Erreur push: ' + putRes.status + ' ' + errBody, true);
      showToast('Erreur push GitHub');
    }
  } catch (err) {
    githubLog('Erreur réseau: ' + err.message, true);
    showToast('Erreur: ' + err.message);
  }
}

var _autoPushTimer = null;
function scheduleAutoPush() {
  if (!getGithubAutoPush()) return;
  if (_autoPushTimer) clearTimeout(_autoPushTimer);
  _autoPushTimer = setTimeout(function() {
    var cfg = getGithubConfig();
    if (cfg.pat) pushDbToGithub();
  }, 2000);
}

function wireGithubSync() {
  var patInput = document.getElementById('github-pat-input');
  var repoInput = document.getElementById('github-repo-input');
  var branchInput = document.getElementById('github-branch-input');
  var pathInput = document.getElementById('github-path-input');
  var pushBtn = document.getElementById('github-push-btn');
  var saveCfgBtn = document.getElementById('github-save-config-btn');
  var autoPushCheck = document.getElementById('github-auto-push');

  var cfg = getGithubConfig();
  if (patInput) patInput.value = cfg.pat || '';
  if (repoInput) repoInput.value = cfg.repo || '';
  if (branchInput) branchInput.value = cfg.branch || 'main';
  if (pathInput) pathInput.value = cfg.path || 'repo/data/db.json';
  if (autoPushCheck) autoPushCheck.checked = getGithubAutoPush();

  if (saveCfgBtn) {
    saveCfgBtn.addEventListener('click', function() {
      var newCfg = {
        pat: patInput ? patInput.value.trim() : '',
        repo: repoInput ? repoInput.value.trim() : '',
        branch: branchInput ? branchInput.value.trim() : 'main',
        path: pathInput ? pathInput.value.trim() : 'repo/data/db.json'
      };
      saveGithubConfig(newCfg);
      showToast('Config GitHub sauvegardée');
      githubLog('Config sauvegardée');
    });
  }

  if (pushBtn) {
    pushBtn.addEventListener('click', function() {
      var cfg2 = getGithubConfig();
      cfg2.pat = patInput ? patInput.value.trim() : cfg2.pat;
      cfg2.repo = repoInput ? repoInput.value.trim() : cfg2.repo;
      cfg2.branch = branchInput ? branchInput.value.trim() : cfg2.branch;
      cfg2.path = pathInput ? pathInput.value.trim() : cfg2.path;
      saveGithubConfig(cfg2);
      pushDbToGithub();
    });
  }

  if (autoPushCheck) {
    autoPushCheck.addEventListener('change', function() {
      setGithubAutoPush(autoPushCheck.checked);
      showToast(autoPushCheck.checked ? 'Auto-push activé' : 'Auto-push désactivé');
    });
  }
}

function nextDocId(allDocs) {
  const nums = allDocs
    .map(d => parseInt((d.id || '').replace('doc-', ''), 10))
    .filter(n => !isNaN(n));
  const max = nums.length ? Math.max(...nums) : 0;
  return 'doc-' + String(max + 1).padStart(4, '0');
}

/* ---------------- Admin "Documents" tab UI ---------------- */

let editingDocId = null; // null = creating new doc
let editingIsPending = false; // true when editing a pending (unvalidated) doc
let titleAutoFill = true;
let descAutoFill = true;
let titleTimer = null;
let descTimer = null;

function initDocManager() {
  if (!APP.db) {
    console.error('[School-Biblio] APP.db est vide — les listes Niveau/Filière/Matière/Type/Wilaya resteront vides. loadData() n\'a probablement pas terminé avant initDocManager().');
    return;
  }
  populateDocFormSelects();
  renderAdminDocTable();
  wireDocManagerEvents();
  wireImportBackupUI();
  wireExportManifest();
  wireAutoBackupUI();
  wireImportManifest();
  startAutoBackup();
  wireGithubSync();
}

function populateDocFormSelects() {
  const levelSel = document.getElementById('doc-form-level');
  const streamSel = document.getElementById('doc-form-stream');
  const subjectSel = document.getElementById('doc-form-subject');
  const typeSel = document.getElementById('doc-form-type');
  const hostSel = document.getElementById('doc-form-host');
  const wilayaSel = document.getElementById('doc-form-wilaya');
  const trimestreSel = document.getElementById('doc-form-trimestre');

  if (!levelSel || !streamSel || !subjectSel || !typeSel || !hostSel) {
    console.error('[School-Biblio] Un ou plusieurs champs du formulaire document sont introuvables dans le DOM. Vérifie que admin.html contient bien la section #doc-form-section à jour, et vide le cache du navigateur (Ctrl+Maj+R).');
    return;
  }
  levelSel.innerHTML = APP.db.levels.map(grp => `
    <optgroup label="${escapeAttr(localized(grp.name))}">
      ${grp.years.map(y => `<option value="${escapeAttr(y.id)}">${escapeHTML(localized(y.name))}</option>`).join('')}
    </optgroup>
  `).join('');

  streamSel.innerHTML = `<option value="">—</option>` +
    APP.db.streams.map(s => `<option value="${escapeAttr(s.id)}">${escapeHTML(localized(s.name))}</option>`).join('');

  subjectSel.innerHTML = APP.db.subjects.map(s => `<option value="${escapeAttr(s.id)}">${escapeHTML(localized(s.name))}</option>`).join('');

  typeSel.innerHTML = APP.db.documentTypes.map(ty => `<option value="${escapeAttr(ty.id)}">${escapeHTML(localized(ty.name))}</option>`).join('');

  hostSel.innerHTML = `<option value="drive">Google Drive</option><option value="mega">Mega</option><option value="other">Autre</option>`;

  if (wilayaSel) {
    const wilayasList = APP.db.wilayas || [];
    wilayaSel.innerHTML = `<option value="">— ${t('admin.noWilaya')}</option>` +
      `<option value="National">${t('admin.nationalWilaya')}</option>` +
      wilayasList.map(w => `<option value="${escapeAttr(localized(w.name))}">${escapeHTML(w.code)} — ${escapeHTML(localized(w.name))}</option>`).join('');
  }

  if (trimestreSel) {
    const trimestresList = APP.db.trimestres || [];
    trimestreSel.innerHTML = `<option value="">— ${t('admin.noTrimestre')}</option>` +
      trimestresList.map(tr => `<option value="${escapeAttr(tr.id)}">${escapeHTML(localized(tr.name))}</option>`).join('');
  }
}

function renderAdminDocTable() {
  const tbody = document.getElementById('admin-doc-table-body');
  const searchVal = (document.getElementById('admin-doc-search')?.value || '').toLowerCase().trim();

  const pendingDocs = getPendingDocs();
  const hiddenIds = getHiddenIds();
  let docs = [...APP.db.documents].sort((a, b) => (b.year || 0) - (a.year || 0));
  if (searchVal) {
    docs = docs.filter(d => {
      const hay = [localized(d.title), d.id, d.subject, d.level].join(' ').toLowerCase();
      return hay.includes(searchVal);
    });
  }

  const selAllChecked = localStorage.getItem('_inry_select_all') === 'true' ? 'checked' : '';

  let html = '';

  // Toolbar row
  html += `<tr class="selection-toolbar"><td colspan="10" style="padding:0.5rem 1rem;background:var(--surface);border-bottom:1px solid var(--kraft-line);">
    <div style="display:flex;gap:var(--space-2);align-items:center;flex-wrap:wrap;">
      <button class="btn btn-ghost btn-xs" id="select-all-btn">☐ Tout</button>
      <button class="btn btn-ghost btn-xs" id="deselect-all-btn">☐ Aucun</button>
      <span style="color:var(--ink-soft);font-size:var(--fs-xs);" id="sel-count"></span>
      <span style="flex:1;"></span>
      <button class="btn btn-danger btn-xs" id="delete-selected-btn" disabled>🗑 Supprimer</button>
      <button class="btn btn-secondary btn-xs" id="hide-selected-btn" disabled>👁 Masquer</button>
      <button class="btn btn-secondary btn-xs" id="unhide-selected-btn" style="display:none;">👁 Afficher</button>
      <button class="btn btn-primary btn-xs" id="bulk-edit-btn" style="display:none;">✏️ Modifier</button>
    </div>
  </td></tr>`;

  // Bulk edit panel
  html += '<tr id="bulk-edit-panel" style="display:none;"><td colspan="10" style="padding:0.75rem 1rem;background:var(--surface-alt,#f0f4ff);border-bottom:2px solid var(--kraft-line);"><div style="display:flex;gap:var(--space-3);align-items:flex-end;flex-wrap:wrap;"><div style="font-weight:700;font-size:var(--fs-sm);width:100%;">✏️ Modifier la sélection — ne coche que les champs à changer :</div><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-level"> Niveau <select id="bulk-val-level" disabled="disabled" style="display:block;margin-top:2px;"></select></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-stream"> Filière <select id="bulk-val-stream" disabled="disabled" style="display:block;margin-top:2px;"></select></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-subject"> Matière <select id="bulk-val-subject" disabled="disabled" style="display:block;margin-top:2px;"></select></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-type"> Type <select id="bulk-val-type" disabled="disabled" style="display:block;margin-top:2px;"></select></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-year"> Année <input type="number" id="bulk-val-year" disabled="disabled" placeholder="2025" min="2000" max="2099" style="display:block;margin-top:2px;width:90px;"></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-host"> Hébergement <input type="text" id="bulk-val-host" disabled="disabled" list="bulk-datalist-host" placeholder="Google Drive / Mega…" style="display:block;margin-top:2px;width:140px;"></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-wilaya"> Wilaya <select id="bulk-val-wilaya" disabled="disabled" style="display:block;margin-top:2px;"></select></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-trimestre"> Trimestre <select id="bulk-val-trimestre" disabled="disabled" style="display:block;margin-top:2px;"></select></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-source"> Source <input type="text" id="bulk-val-source" disabled="disabled" placeholder="…" style="display:block;margin-top:2px;width:120px;"></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-url-source"> URL Source <input type="url" id="bulk-val-url-source" disabled="disabled" list="bulk-datalist-url-source" placeholder="https://…" style="display:block;margin-top:2px;width:180px;"></label><label style="font-size:var(--fs-xs);"><input type="checkbox" id="bulk-chk-url-pdf"> URL PDF <input type="url" id="bulk-val-url-pdf" disabled="disabled" list="bulk-datalist-url-pdf" placeholder="https://…" style="display:block;margin-top:2px;width:180px;"></label><button class="btn btn-primary btn-xs" id="bulk-apply-btn">✅ Appliquer</button><button class="btn btn-ghost btn-xs" id="bulk-cancel-btn">✖ Annuler</button><span id="bulk-confirm" style="color:var(--green);font-size:var(--fs-xs);font-weight:600;"></span><datalist id="bulk-datalist-host"><option value="Google Drive"><option value="Mega"><option value="Autre"></datalist><datalist id="bulk-datalist-url-source"></datalist><datalist id="bulk-datalist-url-pdf"></datalist></div></td></tr>';

  // Pending section
  if (pendingDocs.length) {
    html += `<tr class="pending-section-header"><td colspan="10" style="padding:0.75rem 1rem;background:var(--gold);color:var(--ink);font-weight:700;">⏳ ${pendingDocs.length} document(s) en attente de validation</td></tr>`;
    pendingDocs.forEach(doc => {
      const subject = APP.db.subjects.find(s => s.id === doc.subject);
      const typeName = APP.db.documentTypes.find(ty => ty.id === doc.type);
      const isHidden = hiddenIds.includes(doc.id);
      html += `
        <tr data-doc-id="${escapeAttr(doc.id)}" style="background:var(--cream);${isHidden ? 'opacity:0.5;' : ''}">
          <td><input type="checkbox" class="doc-select-cb" data-doc-id="${escapeAttr(doc.id)}" ${selAllChecked}></td>
          <td class="doc-table-title">${escapeHTML(localized(doc.title))} <span class="local-tag" style="background:var(--gold);color:var(--ink);">en attente</span>${isHidden ? ' <span class="local-tag" style="background:var(--ink-soft);">masqué</span>' : ''}</td>
          <td>${escapeHTML(subject ? localized(subject.name) : doc.subject)}</td>
          <td>${escapeHTML(typeName ? localized(typeName.name) : doc.type)}</td>
          <td>—</td>
          <td class="ltr-only">${escapeHTML(doc.year || '—')}</td>
          <td style="text-transform:capitalize;">${escapeHTML(doc.host)}</td>
          <td class="doc-table-source" style="text-transform:capitalize;">${escapeHTML(doc.source || '—')}</td>
          <td style="white-space:nowrap;">${doc.urlSource ? `<button class="btn-source-eye" data-url="${escapeAttr(doc.urlSource)}" title="Voir la source">📄</button>` : ''}${doc.previewUrl || doc.downloadUrl || doc.urlPdf ? `<button class="btn-preview-pdf" data-url="${escapeAttr(doc.previewUrl || doc.downloadUrl || doc.urlPdf)}" title="Aperçu PDF">👁</button>` : ''}${!doc.urlSource && !doc.previewUrl && !doc.urlPdf && !doc.downloadUrl ? '—' : ''}</td>
          <td class="doc-table-actions">
            <button class="btn btn-secondary btn-sm edit-pending-btn" data-doc-id="${escapeAttr(doc.id)}">${icon('settings')}</button>
            <button class="btn btn-primary btn-sm approve-pending-btn" data-doc-id="${escapeAttr(doc.id)}">✓ Valider</button>
            <button class="btn btn-danger btn-sm reject-pending-btn" data-doc-id="${escapeAttr(doc.id)}">✕ Rejeter</button>
          </td>
        </tr>
      `;
    });
    html += `<tr><td colspan="10" style="padding:0.5rem 1rem;"><button class="btn btn-primary btn-sm" id="approve-all-pending-btn">✓ Tout valider</button></td></tr>`;
  }

  // Published section
  if (docs.length) {
    html += `<tr class="pending-section-header"><td colspan="10" style="padding:0.75rem 1rem;background:var(--kraft);font-weight:600;">✅ Documents publiés (${docs.length})</td></tr>`;
    html += docs.map(doc => {
      const subject = APP.db.subjects.find(s => s.id === doc.subject);
      const typeName = APP.db.documentTypes.find(ty => ty.id === doc.type);
      const trimestreName = APP.db.trimestres?.find(tr => tr.id === doc.trimestre);
      const isLocal = getLocalDocs().some(d => d.id === doc.id);
      const isHidden = hiddenIds.includes(doc.id);
      return `
        <tr data-doc-id="${escapeAttr(doc.id)}"${isHidden ? ' style="opacity:0.5;"' : ''}>
          <td><input type="checkbox" class="doc-select-cb" data-doc-id="${escapeAttr(doc.id)}" ${selAllChecked}></td>
          <td class="doc-table-title">${escapeHTML(localized(doc.title))} ${isLocal ? '<span class="local-tag">local</span>' : ''}${isHidden ? ' <span class="local-tag" style="background:var(--ink-soft);">masqué</span>' : ''}</td>
          <td>${escapeHTML(subject ? localized(subject.name) : '—')}</td>
          <td>${escapeHTML(typeName ? localized(typeName.name) : doc.type)}</td>
          <td>${escapeHTML(trimestreName ? localized(trimestreName.name) : '—')}</td>
          <td class="ltr-only">${escapeHTML(doc.year || '—')}</td>
          <td style="text-transform:capitalize;">${escapeHTML(doc.host)}</td>
          <td class="doc-table-source" style="text-transform:capitalize;">${escapeHTML(doc.source || '—')}</td>
          <td style="white-space:nowrap;">${doc.urlSource ? `<button class="btn-source-eye" data-url="${escapeAttr(doc.urlSource)}" title="Voir la source">📄</button>` : ''}${doc.previewUrl || doc.downloadUrl || doc.urlPdf ? `<button class="btn-preview-pdf" data-url="${escapeAttr(doc.previewUrl || doc.downloadUrl || doc.urlPdf)}" title="Aperçu PDF">👁</button>` : ''}${!doc.urlSource && !doc.previewUrl && !doc.urlPdf && !doc.downloadUrl ? '—' : ''}</td>
          <td class="doc-table-actions">
            <button class="btn btn-secondary btn-sm edit-doc-btn" data-doc-id="${escapeAttr(doc.id)}">${icon('settings')}</button>
            <button class="btn btn-danger btn-sm delete-doc-btn" data-doc-id="${escapeAttr(doc.id)}">${icon('trash')}</button>
          </td>
        </tr>
      `;
    }).join('');
  }

  if (!html) {
    html = `<tr><td colspan="10" style="text-align:center; padding:1.5rem; color:var(--ink-soft);">${t('empty.title')}</td></tr>`;
  }

  tbody.innerHTML = html;

  // Wire selection toolbar
  const selCountEl = document.getElementById('sel-count');
  const deleteSelBtn = document.getElementById('delete-selected-btn');
  const hideSelBtn = document.getElementById('hide-selected-btn');
  const unhideSelBtn = document.getElementById('unhide-selected-btn');

  function updateSelectionUI() {
    const checked = tbody.querySelectorAll('.doc-select-cb:checked');
    const count = checked.length;
    const hiddenIds = getHiddenIds();
    const hasHidden = [...checked].some(cb => hiddenIds.includes(cb.dataset.docId));
    const hasVisible = [...checked].some(cb => !hiddenIds.includes(cb.dataset.docId));
    if (selCountEl) selCountEl.textContent = count ? count + ' sélectionné(s)' : '';
    if (deleteSelBtn) deleteSelBtn.disabled = count === 0;
    if (hideSelBtn) { hideSelBtn.disabled = count === 0; hideSelBtn.style.display = hasVisible ? '' : 'none'; }
    if (unhideSelBtn) { unhideSelBtn.style.display = hasHidden ? '' : 'none'; }
  }

  tbody.querySelectorAll('.doc-select-cb').forEach(cb => {
    cb.addEventListener('change', updateSelectionUI);
  });

  document.getElementById('select-all-btn')?.addEventListener('click', () => {
    tbody.querySelectorAll('.doc-select-cb').forEach(cb => { cb.checked = true; });
    localStorage.setItem('_inry_select_all', 'true');
    updateSelectionUI();
  });
  document.getElementById('deselect-all-btn')?.addEventListener('click', () => {
    tbody.querySelectorAll('.doc-select-cb').forEach(cb => { cb.checked = false; });
    localStorage.setItem('_inry_select_all', 'false');
    updateSelectionUI();
  });

  // Header select-all checkbox
  const selectAllHeader = document.getElementById('select-all-docs');
  if (selectAllHeader) {
    selectAllHeader.checked = selAllChecked === 'checked';
    selectAllHeader.addEventListener('change', () => {
      const checked = selectAllHeader.checked;
      tbody.querySelectorAll('.doc-select-cb').forEach(cb => { cb.checked = checked; });
      localStorage.setItem('_inry_select_all', checked ? 'true' : 'false');
      updateSelectionUI();
    });
  }

  if (deleteSelBtn) {
    deleteSelBtn.addEventListener('click', () => {
      const ids = [...tbody.querySelectorAll('.doc-select-cb:checked')].map(cb => cb.dataset.docId);
      const ok = window.confirm('Supprimer ' + ids.length + ' document(s) définitivement ?');
      if (!ok) return;
      ids.forEach(id => {
        deleteDocEverywhere(id);
        // also remove from pending if present
        const pending = getPendingDocs().filter(d => d.id !== id);
        savePendingDocs(pending);
      });
      applyLocalDocOverrides();
      if (typeof syncDbToGas === 'function') syncDbToGas(APP.db);
      renderAdminDocTable();
      showToast(ids.length + ' document(s) supprimé(s)');
    });
  }

  if (hideSelBtn) {
    hideSelBtn.addEventListener('click', () => {
      const ids = [...tbody.querySelectorAll('.doc-select-cb:checked')].map(cb => cb.dataset.docId);
      const hidden = getHiddenIds();
      ids.forEach(id => { if (!hidden.includes(id)) hidden.push(id); });
      saveHiddenIds(hidden);
      renderAdminDocTable();
      showToast(ids.length + ' document(s) masqué(s)');
    });
  }

  if (unhideSelBtn) {
    unhideSelBtn.addEventListener('click', () => {
      const ids = [...tbody.querySelectorAll('.doc-select-cb:checked')].map(cb => cb.dataset.docId);
      const hidden = getHiddenIds().filter(id => !ids.includes(id));
      saveHiddenIds(hidden);
      renderAdminDocTable();
      showToast(ids.length + ' document(s) ré-affiché(s)');
    });
  }

  const bulkEditBtn = document.getElementById('bulk-edit-btn');
  const bulkPanel = document.getElementById('bulk-edit-panel');
  if (bulkEditBtn) {
    const origUpdateSelectionUI = updateSelectionUI;
    updateSelectionUI = function() {
      origUpdateSelectionUI();
      const count = tbody.querySelectorAll('.doc-select-cb:checked').length;
      bulkEditBtn.disabled = count === 0;
      bulkEditBtn.style.display = count === 0 ? 'none' : '';
    };
  }

  if (bulkEditBtn && bulkPanel) {
    const bulkLevels = document.getElementById('bulk-val-level');
    const bulkStreams = document.getElementById('bulk-val-stream');
    const bulkSubjects = document.getElementById('bulk-val-subject');
    const bulkTypes = document.getElementById('bulk-val-type');
    const bulkYear = document.getElementById('bulk-val-year');
    var bulkHost = document.getElementById('bulk-val-host');
    const bulkWilayas = document.getElementById('bulk-val-wilaya');
    const bulkTrimestres = document.getElementById('bulk-val-trimestre');
    const bulkSource = document.getElementById('bulk-val-source');
    const bulkUrlSource = document.getElementById('bulk-val-url-source');
    const bulkUrlPdf = document.getElementById('bulk-val-url-pdf');

    if (bulkLevels) bulkLevels.innerHTML = '<option value="">— choisir —</option>' + (APP.db.levels || []).map(l => '<option value="' + escapeAttr(l.id) + '">' + escapeHTML(localized(l.name)) + '</option>').join('');
    if (bulkStreams) bulkStreams.innerHTML = '<option value="">— choisir —</option>' + (APP.db.streams || []).map(s => '<option value="' + escapeAttr(s.id) + '">' + escapeHTML(localized(s.name)) + '</option>').join('');
    if (bulkSubjects) bulkSubjects.innerHTML = '<option value="">— choisir —</option>' + (APP.db.subjects || []).map(s => '<option value="' + escapeAttr(s.id) + '">' + escapeHTML(localized(s.name)) + '</option>').join('');
    if (bulkTypes) bulkTypes.innerHTML = '<option value="">— choisir —</option>' + (APP.db.documentTypes || []).map(ty => '<option value="' + escapeAttr(ty.id) + '">' + escapeHTML(localized(ty.name)) + '</option>').join('');
    // Populate URL datalists from existing documents
    var urlSourceVals = [...new Set((APP.db.documents || []).map(function(d) { return d.urlSource; }).filter(Boolean))];
    var urlPdfVals = [...new Set((APP.db.documents || []).map(function(d) { return d.previewUrl || d.downloadUrl || d.urlPdf; }).filter(Boolean))];
    var dlUrlSource = document.getElementById('bulk-datalist-url-source');
    var dlUrlPdf = document.getElementById('bulk-datalist-url-pdf');
    if (dlUrlSource) dlUrlSource.innerHTML = urlSourceVals.map(function(u) { return '<option value="' + escapeAttr(u) + '">'; }).join('');
    if (dlUrlPdf) dlUrlPdf.innerHTML = urlPdfVals.map(function(u) { return '<option value="' + escapeAttr(u) + '">'; }).join('');
    if (bulkWilayas) {
      const wOpts = (APP.db.wilayas || []).map(w => '<option value="' + escapeAttr(w.code || w.id) + '">' + escapeAttr(w.code || w.id) + ' — ' + escapeHTML(localized(w.name)) + '</option>').join('');
      bulkWilayas.innerHTML = '<option value="">— choisir —</option>' + wOpts;
    }
    if (bulkTrimestres) bulkTrimestres.innerHTML = '<option value="">— choisir —</option>' + (APP.db.trimestres || []).map(tr => '<option value="' + escapeAttr(tr.id) + '">' + escapeHTML(localized(tr.name)) + '</option>').join('');

    ['bulk-chk-level','bulk-chk-stream','bulk-chk-subject','bulk-chk-type','bulk-chk-year','bulk-chk-host','bulk-chk-wilaya','bulk-chk-trimestre','bulk-chk-source','bulk-chk-url-source','bulk-chk-url-pdf'].forEach(cId => {
      const c = document.getElementById(cId);
      if (c) c.addEventListener('change', () => {
        const ctrl = c.parentElement.querySelector('select, input[type="number"], input[type="text"], input[type="url"]');
        if (ctrl) ctrl.disabled = !c.checked;
      });
    });

    bulkEditBtn.addEventListener('click', () => {
      bulkPanel.style.display = bulkPanel.style.display === 'none' ? '' : 'none';
      const bc = document.getElementById('bulk-confirm');
      if (bc) bc.textContent = '';
    });

    document.getElementById('bulk-cancel-btn')?.addEventListener('click', () => { bulkPanel.style.display = 'none'; });

    document.getElementById('bulk-apply-btn')?.addEventListener('click', () => {
      const ids = [...tbody.querySelectorAll('.doc-select-cb:checked')].map(cb => cb.dataset.docId);
      if (!ids.length) return;
      const fields = {};
      if (document.getElementById('bulk-chk-level')?.checked) fields.level = bulkLevels.value || null;
      if (document.getElementById('bulk-chk-stream')?.checked) fields.stream = bulkStreams.value || null;
      if (document.getElementById('bulk-chk-subject')?.checked) fields.subject = bulkSubjects.value || null;
      if (document.getElementById('bulk-chk-type')?.checked) fields.type = bulkTypes.value;
      if (document.getElementById('bulk-chk-year')?.checked && bulkYear.value) fields.year = parseInt(bulkYear.value, 10);
      if (document.getElementById('bulk-chk-host')?.checked) fields.host = bulkHost.value.trim() || null;
      if (document.getElementById('bulk-chk-wilaya')?.checked) fields.wilaya = bulkWilayas.value || null;
      if (document.getElementById('bulk-chk-trimestre')?.checked) fields.trimestre = bulkTrimestres.value || null;
      if (document.getElementById('bulk-chk-source')?.checked && bulkSource.value.trim()) fields.source = bulkSource.value.trim();
      if (document.getElementById('bulk-chk-url-source')?.checked && bulkUrlSource.value.trim()) fields.urlSource = bulkUrlSource.value.trim();
      if (document.getElementById('bulk-chk-url-pdf')?.checked && bulkUrlPdf.value.trim()) fields.urlPdf = bulkUrlPdf.value.trim();
      if (!Object.keys(fields).length) { showToast('Coche au moins un champ'); return; }
      let count = 0;
      (APP.db.documents || []).forEach(doc => { if (ids.includes(doc.id)) { Object.assign(doc, fields); count++; } });
      try {
        const pending = getPendingDocs();
        if (pending.length) { pending.forEach(doc => { if (ids.includes(doc.id)) { Object.assign(doc, fields); count++; } }); savePendingDocs(pending); }
      } catch(e) { console.error('Bulk edit pending error:', e); }
      applyLocalDocOverrides();
      renderAdminDocTable();
      const bc = document.getElementById('bulk-confirm');
      if (bc) bc.textContent = '✅ ' + count + ' document(s) modifié(s)';
      showToast(count + ' document(s) modifié(s)');
    });
  }

  // Existing button handlers
  tbody.querySelectorAll('.edit-doc-btn').forEach(btn => {
    btn.addEventListener('click', () => openDocFormForEdit(btn.dataset.docId));
  });
  tbody.querySelectorAll('.delete-doc-btn').forEach(btn => {
    btn.addEventListener('click', () => confirmDeleteDoc(btn.dataset.docId));
  });
  tbody.querySelectorAll('.edit-pending-btn').forEach(btn => {
    btn.addEventListener('click', () => openDocFormForEdit(btn.dataset.docId));
  });
  tbody.querySelectorAll('.approve-pending-btn').forEach(btn => {
    btn.addEventListener('click', () => approvePendingDoc(btn.dataset.docId));
  });
  tbody.querySelectorAll('.reject-pending-btn').forEach(btn => {
    btn.addEventListener('click', () => rejectPendingDoc(btn.dataset.docId));
  });
  const approveAllBtn = document.getElementById('approve-all-pending-btn');
  if (approveAllBtn) approveAllBtn.addEventListener('click', approveAllPending);

  tbody.querySelectorAll('.btn-source-eye').forEach(btn => {
    btn.addEventListener('click', () => window.open(btn.dataset.url, '_blank'));
  });
  tbody.querySelectorAll('.btn-preview-pdf').forEach(btn => {
    btn.addEventListener('click', () => window.open(btn.dataset.url, '_blank'));
  });

  updateSelectionUI();
}

function openDocFormForEdit(docId) {
  let doc = APP.db.documents.find(d => d.id === docId);
  editingIsPending = false;
  if (!doc) {
    doc = getPendingDocs().find(d => d.id === docId);
    if (!doc) return;
    editingIsPending = true;
  }
  editingDocId = docId;

  // Reset auto-translate state so modifying French re-triggers translation
  titleAutoFill = true;
  descAutoFill = true;
  ['doc-form-title-ar','doc-form-title-en','doc-form-desc-ar','doc-form-desc-en'].forEach(id => {
    const el = document.getElementById(id);
    if (el) { el.dataset.autofilled = 'true'; }
  });

  document.getElementById('doc-form-title-fr').value = doc.title.fr || '';
  document.getElementById('doc-form-title-ar').value = doc.title.ar || '';
  document.getElementById('doc-form-title-en').value = doc.title.en || '';
  document.getElementById('doc-form-desc-fr').value = doc.description?.fr || '';
  document.getElementById('doc-form-desc-ar').value = doc.description?.ar || '';
  document.getElementById('doc-form-desc-en').value = doc.description?.en || '';

  // Trigger translation for any filled French field (regardless of ar/en existing)
  if (doc.title.fr) {
    document.getElementById('doc-form-title-fr').dispatchEvent(new Event('input', { bubbles: true }));
  }
  if (doc.description?.fr) {
    document.getElementById('doc-form-desc-fr').dispatchEvent(new Event('input', { bubbles: true }));
  }
  document.getElementById('doc-form-level').value = doc.level || '';
  document.getElementById('doc-form-stream').value = doc.stream || '';
  document.getElementById('doc-form-subject').value = doc.subject || '';
  document.getElementById('doc-form-type').value = doc.type || '';
  document.getElementById('doc-form-year').value = doc.year || '';
  document.getElementById('doc-form-trimestre').value = doc.trimestre || '';
  document.getElementById('doc-form-wilaya').value = doc.wilaya || '';
  document.getElementById('doc-form-pages').value = doc.pages || '';
  document.getElementById('doc-form-size').value = doc.size || '';
  document.getElementById('doc-form-host').value = doc.host || 'drive';
  document.getElementById('doc-form-preview-url').value = doc.previewUrl || '';
  document.getElementById('doc-form-download-url').value = doc.downloadUrl || '';
  document.getElementById('doc-form-source').value = doc.source || '';
  document.getElementById('doc-form-url-source').value = doc.urlSource || '';
  document.getElementById('doc-form-url-pdf').value = doc.urlPdf || '';

  // Auto-fetch file info from stored URLs (silently, only if fields are empty or placeholder)
  const previewUrl = doc.previewUrl || doc.downloadUrl;
  if (previewUrl) {
    const sizeField = document.getElementById('doc-form-size');
    const pagesField = document.getElementById('doc-form-pages');
    const currentPages = doc.pages || '';
    const currentSize = doc.size || '';
    if (!sizeField.value || sizeField.value === '—' || !currentSize || currentSize === '—') {
      tryFetchFileSize(previewUrl).then(s => { if (s && !sizeField.value) sizeField.value = s; });
    }
    if (!pagesField.value || pagesField.value === '—' || !currentPages || currentPages === '—') {
      tryFetchPageCount(previewUrl).then(p => { if (p && !pagesField.value) pagesField.value = String(p); });
    }
  }

  document.getElementById('doc-form-title-heading').textContent = t('admin.editDoc');
  document.getElementById('doc-form-submit-btn').textContent = t('admin.saveChanges');

  // Switch to Ajouter sub-tab
  document.querySelectorAll('.admin-sub-tab').forEach(function(b) { b.classList.remove('active'); });
  document.querySelector('.admin-sub-tab[data-subtab="docs-add"]')?.classList.add('active');
  document.querySelectorAll('#tab-panel-docs .admin-sub-panel').forEach(function(p) { p.classList.add('hidden'); });
  document.getElementById('sub-panel-docs-add')?.classList.remove('hidden');
  document.getElementById('sub-panel-docs-add')?.scrollIntoView?.({ behavior: 'smooth', block: 'start' });
}

function resetDocForm() {
  editingDocId = null;
  editingIsPending = false;
  document.getElementById('doc-form').reset();
  document.getElementById('doc-form-title-heading').textContent = t('admin.addDoc');
  document.getElementById('doc-form-submit-btn').textContent = t('admin.save');
  // Reset auto-translate state
  titleAutoFill = true;
  descAutoFill = true;
  ['doc-form-title-ar','doc-form-title-en','doc-form-desc-ar','doc-form-desc-en'].forEach(id => {
    const el = document.getElementById(id);
    if (el) { el.dataset.autofilled = 'false'; el.placeholder = ''; }
  });
  if (titleTimer) clearTimeout(titleTimer);
  if (descTimer) clearTimeout(descTimer);
}

function confirmDeleteDoc(docId) {
  const doc = APP.db.documents.find(d => d.id === docId);
  if (!doc) return;
  const ok = window.confirm(t('admin.confirmDelete') + '\n\n"' + localized(doc.title) + '"');
  if (!ok) return;

  deleteDocEverywhere(docId);
  applyLocalDocOverrides();
  syncDbToGas(APP.db);
  renderAdminDocTable();
  showToast(t('admin.docDeleted'));
  if (editingDocId === docId) resetDocForm();
}

async function tryFetchFileSize(url) {
  if (!url) return null;
  try {
    const res = await fetch(url, { method: 'HEAD' });
    const len = res.headers.get('Content-Length');
    if (len && parseInt(len) > 0) return formatFileSize(parseInt(len));
  } catch { /* ignore CORS/network errors */ }
  return null;
}

async function tryFetchPageCount(url) {
  if (!url) return null;
  try {
    const res = await fetch(url, { headers: { Range: 'bytes=0-15360' } });
    const text = await res.text();
    const pagesMatch = text.match(/\/Type\s*\/Pages[^>]*\/Count\s+(\d+)/);
    if (pagesMatch && pagesMatch[1]) {
      const count = parseInt(pagesMatch[1], 10);
      if (count > 0 && count < 500) return count;
    }
  } catch { /* ignore CORS/network errors */ }
  return null;
}

function formatFileSize(bytes) {
  if (bytes < 1024) return bytes + ' B';
  if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
  if (bytes < 1024 * 1024 * 1024) return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
  return (bytes / (1024 * 1024 * 1024)).toFixed(1) + ' GB';
}

async function translateText(text, targetLang) {
  if (!text.trim()) return '';
  try {
    const url = `https://api.mymemory.translated.net/get?q=${encodeURIComponent(text.slice(0, 500))}&langpair=fr|${targetLang}`;
    const res = await fetch(url);
    const data = await res.json();
    return data.responseData?.translatedText || text;
  } catch {
    return text;
  }
}

function wireDocManagerEvents() {
  const form = document.getElementById('doc-form');

  // Auto-translate Arabic and English from French title
  const titleFr = document.getElementById('doc-form-title-fr');
  const titleAr = document.getElementById('doc-form-title-ar');
  const titleEn = document.getElementById('doc-form-title-en');
  titleAutoFill = true;
  titleTimer = null;
  function isAutoTranslateOn() {
    var cb = document.getElementById('auto-translate-toggle');
    return cb && cb.checked;
  }
  titleFr.addEventListener('input', () => {
    if (!titleAutoFill || !isAutoTranslateOn()) return;
    clearTimeout(titleTimer);
    const val = titleFr.value;
    if (!val) { titleAr.value = ''; titleEn.value = ''; return; }
    titleTimer = setTimeout(async () => {
      if (titleAr.value === '' || titleAr.dataset.autofilled === 'true') {
        titleAr.dataset.autofilled = 'true';
        titleAr.placeholder = '...';
        titleAr.value = await translateText(val, 'ar');
        if (titleAr.dataset.autofilled === 'true') titleAr.placeholder = '';
      }
      if (titleEn.value === '' || titleEn.dataset.autofilled === 'true') {
        titleEn.dataset.autofilled = 'true';
        titleEn.placeholder = '...';
        titleEn.value = await translateText(val, 'en');
        if (titleEn.dataset.autofilled === 'true') titleEn.placeholder = '';
      }
    }, 600);
  });
  titleAr.addEventListener('input', () => { titleAr.dataset.autofilled = 'false'; titleAutoFill = false; });
  titleEn.addEventListener('input', () => { titleEn.dataset.autofilled = 'false'; titleAutoFill = false; });

  // Auto-translate Arabic and English from French description
  const descFr = document.getElementById('doc-form-desc-fr');
  const descAr = document.getElementById('doc-form-desc-ar');
  const descEn = document.getElementById('doc-form-desc-en');
  descAutoFill = true;
  descTimer = null;
  descFr.addEventListener('input', () => {
    if (!descAutoFill || !isAutoTranslateOn()) return;
    clearTimeout(descTimer);
    const val = descFr.value;
    if (!val) { descAr.value = ''; descEn.value = ''; return; }
    descTimer = setTimeout(async () => {
      if (descAr.value === '' || descAr.dataset.autofilled === 'true') {
        descAr.dataset.autofilled = 'true';
        descAr.placeholder = '...';
        descAr.value = await translateText(val, 'ar');
        if (descAr.dataset.autofilled === 'true') descAr.placeholder = '';
      }
      if (descEn.value === '' || descEn.dataset.autofilled === 'true') {
        descEn.dataset.autofilled = 'true';
        descEn.placeholder = '...';
        descEn.value = await translateText(val, 'en');
        if (descEn.dataset.autofilled === 'true') descEn.placeholder = '';
      }
    }, 600);
  });
  descAr.addEventListener('input', () => { descAr.dataset.autofilled = 'false'; descAutoFill = false; });
  descEn.addEventListener('input', () => { descEn.dataset.autofilled = 'false'; descAutoFill = false; });

  // Auto-fetch file info from URL (paste + on input when empty)
  const previewUrl = document.getElementById('doc-form-preview-url');
  const downloadUrl = document.getElementById('doc-form-download-url');
  const sizeField = document.getElementById('doc-form-size');
  const pagesField = document.getElementById('doc-form-pages');
  async function tryAutoFetchFromUrl(url) {
    if (!url) return;
    if (!sizeField.value) {
      const size = await tryFetchFileSize(url);
      if (size) sizeField.value = size;
    }
    if (!pagesField.value) {
      const pages = await tryFetchPageCount(url);
      if (pages) pagesField.value = pages;
    }
  }
  [previewUrl, downloadUrl].forEach(field => {
    if (!field) return;
    field.addEventListener('paste', () => {
      setTimeout(() => tryAutoFetchFromUrl(field.value.trim()), 100);
    });
    field.addEventListener('input', () => {
      if (field.value.trim()) {
        setTimeout(() => tryAutoFetchFromUrl(field.value.trim()), 300);
      }
    });
  });

  // TAB key → fill field from placeholder
  document.querySelectorAll('#doc-form input, #doc-form textarea').forEach(el => {
    el.addEventListener('keydown', (e) => {
      if (e.key === 'Tab' && !el.value && el.placeholder) {
        el.value = el.placeholder;
      }
    });
  });

  form.addEventListener('submit', (e) => {
    e.preventDefault();

    const titleFr = document.getElementById('doc-form-title-fr').value.trim();
    const titleAr = document.getElementById('doc-form-title-ar').value.trim();
    const titleEn = document.getElementById('doc-form-title-en').value.trim();
    const previewUrl = document.getElementById('doc-form-preview-url').value.trim();
    const downloadUrl = document.getElementById('doc-form-download-url').value.trim();

    if (!titleFr || !previewUrl || !downloadUrl) {
      showToast(t('admin.requiredFieldsMissing'));
      return;
    }

    const id = editingDocId || nextDocId(APP.db.documents);
    const existing = editingDocId ? APP.db.documents.find(d => d.id === editingDocId) : null;
    const existingPending = editingDocId && !existing ? getPendingDocs().find(d => d.id === editingDocId) : null;

    const doc = {
      id,
      title: { fr: titleFr, ar: titleAr || titleFr, en: titleEn || titleFr },
      level: document.getElementById('doc-form-level').value,
      stream: document.getElementById('doc-form-stream').value || null,
      subject: document.getElementById('doc-form-subject').value,
      type: document.getElementById('doc-form-type').value,
      year: parseInt(document.getElementById('doc-form-year').value, 10) || new Date().getFullYear(),
      trimestre: document.getElementById('doc-form-trimestre').value || null,
      wilaya: document.getElementById('doc-form-wilaya').value.trim() || null,
      description: {
        fr: document.getElementById('doc-form-desc-fr').value.trim(),
        ar: document.getElementById('doc-form-desc-ar').value.trim(),
        en: document.getElementById('doc-form-desc-en').value.trim()
      },
      fileType: 'pdf',
      pages: parseInt(document.getElementById('doc-form-pages').value, 10) || 1,
      size: document.getElementById('doc-form-size').value.trim() || '—',
      previewUrl,
      downloadUrl,
      source: document.getElementById('doc-form-source').value.trim() || '',
      urlSource: document.getElementById('doc-form-url-source').value.trim() || '',
      urlPdf: document.getElementById('doc-form-url-pdf').value.trim() || '',
      host: document.getElementById('doc-form-host').value,
      downloads: existing?.downloads || existingPending?.downloads || 0,
      rating: existing?.rating || existingPending?.rating || 0,
      tags: existing?.tags || existingPending?.tags || []
    };

    if (editingIsPending) {
      const pending = getPendingDocs();
      const idx = pending.findIndex(d => d.id === id);
      if (idx >= 0) pending[idx] = doc;
      else pending.push(doc);
      savePendingDocs(pending);
    } else {
      upsertLocalDoc(doc);
      applyLocalDocOverrides();
      syncDbToGas(APP.db);
    }
    renderAdminDocTable();
    resetDocForm();
    showToast(editingDocId ? t('admin.docUpdated') : t('admin.docAdded'));
  });

  document.getElementById('doc-form-cancel-btn').addEventListener('click', resetDocForm);

  const searchInput = document.getElementById('admin-doc-search');
  if (searchInput) {
    searchInput.addEventListener('input', debounce(renderAdminDocTable, 200));
  }

  document.getElementById('export-db-btn').addEventListener('click', exportDbJson);

  // Spell check descriptions via AI
  const spellCheckBtn = document.getElementById('spell-check-btn');
  if (spellCheckBtn) {
    spellCheckBtn.addEventListener('click', async () => {
      const frText = document.getElementById('doc-form-desc-fr').value.trim();
      if (!frText) { showToast('Remplis d\'abord la description en français.'); return; }
      const key = typeof getSelectedKey === 'function' ? getSelectedKey() : null;
      if (!key && typeof getActiveKey === 'function') {
        // fallback to any stored key
        if (typeof getStoredKeys === 'function') {
          const keys = getStoredKeys();
          if (keys.length) {
            spellCheckBtn.textContent = '⏳ Correction…';
            spellCheckBtn.disabled = true;
            try {
              const corrected = await correctTextWithAI(frText, keys[0]);
              if (corrected && corrected !== frText) {
                document.getElementById('doc-form-desc-fr').value = corrected;
                document.getElementById('doc-form-desc-fr').dispatchEvent(new Event('input', { bubbles: true }));
                showToast('Description corrigée !');
              } else {
                showToast('Aucune correction nécessaire.');
              }
            } catch (err) {
              showToast('Erreur: ' + err.message);
            }
            spellCheckBtn.textContent = t('admin.spellCheck') || 'Corriger l\'orthographe (descriptions)';
            spellCheckBtn.disabled = false;
            return;
          }
        }
        showToast('Configure une clé API dans l\'onglet IA.');
        return;
      }
      if (!key) { showToast('Configure une clé API dans l\'onglet IA.'); return; }
      spellCheckBtn.textContent = '⏳ Correction…';
      spellCheckBtn.disabled = true;
      try {
        const corrected = await correctTextWithAI(frText, key);
        if (corrected && corrected !== frText) {
          document.getElementById('doc-form-desc-fr').value = corrected;
          document.getElementById('doc-form-desc-fr').dispatchEvent(new Event('input', { bubbles: true }));
          showToast('Description corrigée !');
        } else {
          showToast('Aucune correction nécessaire.');
        }
      } catch (err) {
        showToast('Erreur: ' + err.message);
      }
      spellCheckBtn.textContent = t('admin.spellCheck') || 'Corriger l\'orthographe (descriptions)';
      spellCheckBtn.disabled = false;
    });
  }
}

async function correctTextWithAI(text, keyConfig) {
  const apiKey = (typeof sanitizeApiKey === 'function') ? sanitizeApiKey(keyConfig.apiKey) : keyConfig.apiKey.trim();
  const prompt = 'Corrige les fautes d\'orthographe et de grammaire du texte suivant en français. Ne change PAS le contenu, corrige UNIQUEMENT les erreurs. Réponds UNIQUEMENT avec le texte corrigé, sans commentaire ni guillemets.\n\n' + text.slice(0, 1000);
  if (keyConfig.provider === 'openai') {
    const res = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + apiKey },
      body: JSON.stringify({ model: keyConfig.model || 'gpt-4.1', messages: [{ role: 'user', content: prompt }], max_tokens: 500 })
    });
    if (!res.ok) throw new Error('HTTP ' + res.status);
    const data = await res.json();
    return data.choices?.[0]?.message?.content?.trim() || text;
  }
  if (keyConfig.provider === 'anthropic') {
    const res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'anthropic-dangerous-direct-browser-access': 'true' },
      body: JSON.stringify({ model: keyConfig.model, max_tokens: 500, messages: [{ role: 'user', content: prompt }] })
    });
    if (!res.ok) throw new Error('HTTP ' + res.status);
    const data = await res.json();
    return (data.content || []).filter(b => b.type === 'text').map(b => b.text).join('\n').trim() || text;
  }
  if (keyConfig.provider === 'google') {
    const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${keyConfig.model}:generateContent?key=${apiKey}`, {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ contents: [{ role: 'user', parts: [{ text: prompt }] }] })
    });
    if (!res.ok) throw new Error('HTTP ' + res.status);
    const data = await res.json();
    return data.candidates?.[0]?.content?.parts?.map(p => p.text).join('\n').trim() || text;
  }
  throw new Error('Fournisseur non supporté pour la correction.');
}

async function exportDbJson() {
  try {
    const exportObj = await buildExportObj();
    const blob = new Blob([JSON.stringify(exportObj, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'db.json';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    saveDbBackup('db.json', exportObj);
    renderDbBackupList();
    showToast(t('admin.exported'));
  } catch (err) {
    console.error('[School-Biblio] Échec de l\'export db.json:', err);
    showToast('Erreur export: ' + err.message);
  }
}

/* ---- PAT Encryption (AES-GCM) ---- */
var GH_PAT_KEY_STORAGE = 'fp_gh_pat_key';

function getOrCreatePatKey() {
  var stored = localStorage.getItem(GH_PAT_KEY_STORAGE);
  if (stored) return stored;
  var arr = new Uint8Array(32);
  crypto.getRandomValues(arr);
  var key = btoa(String.fromCharCode.apply(null, arr));
  localStorage.setItem(GH_PAT_KEY_STORAGE, key);
  return key;
}

async function encryptPat(pat) {
  if (!pat) return null;
  try {
    var keyB64 = getOrCreatePatKey();
    var keyBytes = Uint8Array.from(atob(keyB64), function(c) { return c.charCodeAt(0); });
    var cryptoKey = await crypto.subtle.importKey('raw', keyBytes, 'AES-GCM', false, ['encrypt']);
    var iv = new Uint8Array(12);
    crypto.getRandomValues(iv);
    var encoded = new TextEncoder().encode(pat);
    var encrypted = await crypto.subtle.encrypt({ name: 'AES-GCM', iv: iv }, cryptoKey, encoded);
    return { iv: btoa(String.fromCharCode.apply(null, iv)), data: btoa(String.fromCharCode.apply(null, new Uint8Array(encrypted))) };
  } catch(e) { console.error('PAT encrypt error:', e); return null; }
}

async function buildExportObj() {
  var ghCfg = getGithubConfig();
  return {
    meta: APP.db.meta,
    levels: APP.db.levels,
    streams: APP.db.streams,
    subjects: APP.db.subjects,
    documentTypes: APP.db.documentTypes,
    wilayas: APP.db.wilayas,
    institutions: APP.db.institutions,
    hosts: APP.db.hosts,
    documents: APP.db.documents,
    hidden: {
      docIds: getHiddenIds(),
      levelIds: getEntityHiddenIds('levels'),
      streamIds: getEntityHiddenIds('streams'),
      subjectIds: getEntityHiddenIds('subjects'),
      documentTypeIds: getEntityHiddenIds('documentTypes')
    },
    githubSync: {
      encryptedPAT: await encryptPat(ghCfg.pat),
      patKey: localStorage.getItem(GH_PAT_KEY_STORAGE) || '',
      repo: ghCfg.repo || '',
      branch: ghCfg.branch || 'main',
      path: ghCfg.path || 'repo/data/db.json',
      autoPush: getGithubAutoPush()
    }
  };
}

/* ---- Import db.json & local backups ---- */
const DB_BACKUPS_KEY = 'inry_db_backups';
const MAX_BACKUPS = 5;

function computeDbStats(data) {
  var docs = data.documents || [];
  var total = docs.length;
  var subjects = {}; var types = {}; var years = {};
  docs.forEach(function(d) {
    var s = APP.db.subjects.find(function(s) { return s.id === d.subject; });
    var sn = s ? (localized(s.name) || d.subject) : d.subject;
    subjects[sn] = (subjects[sn] || 0) + 1;
    var t = APP.db.documentTypes.find(function(t) { return t.id === d.type; });
    var tn = t ? (localized(t.name) || d.type) : d.type;
    types[tn] = (types[tn] || 0) + 1;
    if (d.year) years[d.year] = (years[d.year] || 0) + 1;
  });
  var yearRange = Object.keys(years).sort();
  return { total: total, subjects: subjects, types: types, years: yearRange };
}

function getDbBackups() {
  try { return JSON.parse(localStorage.getItem(DB_BACKUPS_KEY)) || []; } catch(e) { return []; }
}

function saveDbBackup(name, data) {
  var json = JSON.stringify(data);
  var sizeBytes = new Blob([json]).size;
  var sizeLabel = sizeBytes < 1024 ? sizeBytes + ' o' : sizeBytes < 1048576 ? (sizeBytes / 1024).toFixed(1) + ' Ko' : (sizeBytes / 1048576).toFixed(1) + ' Mo';
  var stats = computeDbStats(data);
  var backups = getDbBackups();
  backups.unshift({ id: Date.now(), name: name || 'db.json', timestamp: new Date().toISOString(), size: sizeLabel, stats: stats, data: data });
  if (backups.length > MAX_BACKUPS) backups = backups.slice(0, MAX_BACKUPS);
  try { localStorage.setItem(DB_BACKUPS_KEY, JSON.stringify(backups)); } catch(e) { showToast('Stockage local saturé, sauvegarde ignorée.'); }
}

function deleteDbBackup(id) {
  var backups = getDbBackups().filter(function(b) { return b.id !== id; });
  localStorage.setItem(DB_BACKUPS_KEY, JSON.stringify(backups));
}

function renderDbBackupList() {
  var el = document.getElementById('db-backup-list');
  if (!el) return;
  var backups = getDbBackups();
  if (!backups.length) {
    el.innerHTML = '<div style="padding:var(--space-3);font-size:var(--fs-xs);color:var(--ink-soft);text-align:center;">Aucune sauvegarde locale</div>';
    return;
  }
  el.innerHTML = '<div style="font-size:var(--fs-xs);font-weight:600;margin-bottom:var(--space-1);">Sauvegardes locales :</div>' +
    backups.map(function(b) {
      var s = b.stats || {};
      var tooltipParts = [];
      tooltipParts.push('📄 ' + s.total + ' document' + (s.total > 1 ? 's' : ''));
      if (b.size) tooltipParts.push('💾 ' + b.size);
      if (s.years && s.years.length) tooltipParts.push('📅 ' + s.years[0] + (s.years.length > 1 ? '–' + s.years[s.years.length - 1] : ''));
      if (s.subjects) {
        var topSubj = Object.entries(s.subjects).sort(function(a, b) { return b[1] - a[1]; }).slice(0, 5);
        topSubj.forEach(function(kv) { tooltipParts.push('📁 ' + kv[0] + ': ' + kv[1]); });
      }
      if (s.types) {
        Object.entries(s.types).forEach(function(kv) { tooltipParts.push('🏷 ' + kv[0] + ': ' + kv[1]); });
      }
      var tooltipHtml = tooltipParts.length ? tooltipParts.join('<br>') : '';
      return '<div class="db-backup-item" style="display:flex;align-items:center;gap:var(--space-2);padding:var(--space-2);border:1px solid var(--kraft-line);border-radius:var(--radius-sm);margin-bottom:var(--space-1);">' +
        (tooltipHtml ? '<div class="db-backup-tooltip" data-tt="' + escapeHTML(tooltipHtml) + '">' + tooltipHtml + '</div>' : '') +
        '<span style="flex:1;font-size:var(--fs-xs);">' +
          '<strong>' + escapeHTML(b.name || 'db.json') + '</strong>' +
          (b.size ? ' <span style="color:var(--ink-soft);font-size:9px;">(' + escapeHTML(b.size) + ')</span>' : '') +
          '<br><span style="color:var(--ink-soft);font-size:10px;">' + new Date(b.timestamp).toLocaleString() + '</span>' +
        '</span>' +
        '<button class="btn btn-primary btn-sm db-backup-restore-btn" data-backup-id="' + b.id + '">Restaurer</button>' +
        '<button class="btn btn-ghost btn-sm db-backup-del-btn" data-backup-id="' + b.id + '" title="Supprimer">✕</button></div>';
    }).join('');
  el.querySelectorAll('.db-backup-restore-btn').forEach(function(btn) {
    btn.addEventListener('click', function() {
      var backup = getDbBackups().find(function(b) { return b.id === parseInt(btn.dataset.backupId); });
      if (!backup) return;
      if (!confirm('Restaurer la sauvegarde "' + (backup.name || 'db.json') + '" du ' + new Date(backup.timestamp).toLocaleString() + ' ?')) return;
      importDbData(backup.data);
    });
  });
  el.querySelectorAll('.db-backup-del-btn').forEach(function(btn) {
    btn.addEventListener('click', function() {
      deleteDbBackup(parseInt(btn.dataset.backupId));
      renderDbBackupList();
    });
  });
  // Tooltip positioning on hover
  el.querySelectorAll('.db-backup-item').forEach(function(item) {
    var tip = item.querySelector('.db-backup-tooltip');
    if (!tip) return;
    function showTip(e) {
      var rect = item.getBoundingClientRect();
      var tipRect = tip.getBoundingClientRect();
      var tipH = tipRect.height || 120;
      var spaceBelow = window.innerHeight - rect.bottom;
      var spaceAbove = rect.top;
      tip.classList.add('show');
      tip.style.left = Math.min(rect.left, window.innerWidth - 320) + 'px';
      if (spaceBelow >= tipH + 12) {
        tip.style.top = (rect.bottom + 8) + 'px';
        tip.style.bottom = 'auto';
      } else if (spaceAbove >= tipH + 12) {
        tip.style.top = 'auto';
        tip.style.bottom = (window.innerHeight - rect.top + 8) + 'px';
      } else {
        tip.style.top = Math.max(4, rect.top) + 'px';
        tip.style.bottom = 'auto';
      }
    }
    item.addEventListener('mouseenter', showTip);
    item.addEventListener('mousemove', showTip);
    item.addEventListener('mouseleave', function() { tip.classList.remove('show'); });
  });
}

function importDbData(data) {
  try {
    if (!data || !data.meta || !data.documents) {
      showToast('Fichier invalide : structure db.json non reconnue.');
      return;
    }
    localStorage.setItem('inry_custom_db', JSON.stringify(data));
    localStorage.removeItem('inry_local_docs');
    localStorage.removeItem('inry_deleted_ids');
    APP.db = data;
    showToast('Base importée, synchronisation GAS…');
    syncDbToGas(data).then(function() {
      showToast('Synchronisé ! Rechargement…');
      setTimeout(function() { location.reload(); }, 800);
    });
  } catch(err) {
    showToast('Erreur: ' + err.message);
  }
}

/* ---- Auto-backup planifié ---- */

var autoBackupTimer = null;
var AUTO_BACKUP_KEY = 'inry_auto_backup';
var AUTO_BACKUP_LAST_KEY = 'inry_auto_backup_last';
var AUTO_BACKUP_CHECK_INTERVAL = 30000; // check every 30s

function getAutoBackupConfig() {
  try {
    var raw = localStorage.getItem(AUTO_BACKUP_KEY);
    if (!raw) return { mode: 'off' };
    return JSON.parse(raw);
  } catch(e) { return { mode: 'off' }; }
}

function setAutoBackupConfig(cfg) {
  try { localStorage.setItem(AUTO_BACKUP_KEY, JSON.stringify(cfg)); } catch(e) {}
}

function stopAutoBackup() {
  if (autoBackupTimer) { clearInterval(autoBackupTimer); autoBackupTimer = null; }
}

function getDbDataForBackup() {
  var custom = localStorage.getItem('inry_custom_db');
  if (custom) { try { return JSON.parse(custom); } catch(e) {} }
  var local = localStorage.getItem('inry_local_docs');
  var deleted = localStorage.getItem('inry_deleted_ids');
  return {
    meta: APP.db ? APP.db.meta : { version: 1 },
    documents: local ? JSON.parse(local) : (APP.db ? APP.db.documents : []),
    subjects: APP.db ? APP.db.subjects : [],
    documentTypes: APP.db ? APP.db.documentTypes : [],
    studyLevels: APP.db ? APP.db.studyLevels : [],
    removedIds: deleted ? JSON.parse(deleted) : []
  };
}

function shouldRunBackup(cfg) {
  var now = Date.now();
  var last = 0;
  try { last = parseInt(localStorage.getItem(AUTO_BACKUP_LAST_KEY)) || 0; } catch(e) {}
  if (cfg.mode === 'interval') {
    var ms = parseInt(cfg.value) * (cfg.unit === 'minutes' ? 60000 : cfg.unit === 'hours' ? 3600000 : 86400000);
    if (isNaN(ms) || ms <= 0) return false;
    return (now - last) >= ms;
  }
  if (cfg.mode === 'fixed') {
    var d = new Date();
    var target = new Date(d.getFullYear(), d.getMonth(), d.getDate(), parseInt(cfg.hour) || 0, parseInt(cfg.minute) || 0);
    // If target already passed today, schedule for next day
    if (target <= new Date(last)) return false;
    return now >= target.getTime();
  }
  return false;
}

function performAutoBackup() {
  var cfg = getAutoBackupConfig();
  if (cfg.mode === 'off') return;
  if (!shouldRunBackup(cfg)) return;
  var now = Date.now();
  try { localStorage.setItem(AUTO_BACKUP_LAST_KEY, String(now)); } catch(e) {}
  var data = getDbDataForBackup();
  if (!data || !data.documents) return;
  saveDbBackup('auto-' + new Date().toISOString().slice(0,10), data);
}

function startAutoBackup() {
  stopAutoBackup();
  var cfg = getAutoBackupConfig();
  if (cfg.mode === 'off') return;
  performAutoBackup();
  autoBackupTimer = setInterval(performAutoBackup, AUTO_BACKUP_CHECK_INTERVAL);
}

function wireAutoBackupUI() {
  var cfg = getAutoBackupConfig();
  var modeRadios = document.querySelectorAll('input[name="auto-backup-mode"]');
  var intervalGroup = document.getElementById('auto-backup-interval-group');
  var fixedGroup = document.getElementById('auto-backup-fixed-group');

  if (!modeRadios.length) return;
  modeRadios.forEach(function(r) { r.checked = r.value === cfg.mode; });
  toggleAutoBackupGroups(cfg.mode);

  modeRadios.forEach(function(r) {
    r.addEventListener('change', function() {
      toggleAutoBackupGroups(r.value);
    });
  });

  document.getElementById('auto-backup-interval-val').value = cfg.value || 1;
  document.getElementById('auto-backup-interval-unit').value = cfg.unit || 'hours';
  var h = ('0' + (cfg.hour || 8)).slice(-2);
  var m = ('0' + (cfg.minute || 0)).slice(-2);
  document.getElementById('auto-backup-fixed-hour').value = h + ':' + m;

  document.getElementById('auto-backup-save').addEventListener('click', function() {
    var mode = document.querySelector('input[name="auto-backup-mode"]:checked');
    if (!mode) return;
    var newCfg = { mode: mode.value };
    if (mode.value === 'interval') {
      newCfg.value = parseInt(document.getElementById('auto-backup-interval-val').value) || 1;
      newCfg.unit = document.getElementById('auto-backup-interval-unit').value;
    } else if (mode.value === 'fixed') {
      var timeParts = document.getElementById('auto-backup-fixed-hour').value.split(':');
      newCfg.hour = parseInt(timeParts[0]) || 0;
      newCfg.minute = parseInt(timeParts[1]) || 0;
    }
    setAutoBackupConfig(newCfg);
    startAutoBackup();
    showToast(mode.value === 'off' ? 'Sauvegarde automatique désactivée' : 'Sauvegarde automatique activée');
  });
}

function toggleAutoBackupGroups(mode) {
  var intervalGroup = document.getElementById('auto-backup-interval-group');
  var fixedGroup = document.getElementById('auto-backup-fixed-group');
  if (intervalGroup) intervalGroup.style.display = mode === 'interval' ? 'flex' : 'none';
  if (fixedGroup) fixedGroup.style.display = mode === 'fixed' ? 'flex' : 'none';
}

function wireImportBackupUI() {
  document.getElementById('import-db-btn').addEventListener('click', function() {
    var fileInput = document.getElementById('import-db-file-input');
    var file = fileInput.files[0];
    if (!file) { showToast('Sélectionne un fichier db.json d\'abord.'); return; }
    var reader = new FileReader();
    reader.onload = function(e) {
      try {
        var data = JSON.parse(e.target.result);
        importDbData(data);
      } catch(err) {
        showToast('Erreur de lecture du fichier: ' + err.message);
      }
    };
    reader.readAsText(file);
  });

  document.getElementById('reset-db-btn').addEventListener('click', function() {
    if (!confirm('Réinitialiser la base aux données d\'origine ? Toute modification locale sera perdue.')) return;
    localStorage.removeItem('inry_custom_db');
    localStorage.removeItem('inry_local_docs');
    localStorage.removeItem('inry_deleted_ids');
    showToast('Base réinitialisée. Rechargement…');
    setTimeout(function() { location.reload(); }, 800);
  });

  renderDbBackupList();
}

/* ---- Export Manifest JSON ---- */
function getLocalDocs() {
  try { return JSON.parse(localStorage.getItem('inry_local_docs') || '[]'); }
  catch(e) { return []; }
}

function getManifestDocuments() {
  var docs = getLocalDocs();
  return docs.map(function(d) {
    var c = Object.assign({}, d);
    if (c.title && typeof c.title === 'object') {
      c.title = c.title.fr || c.title.ar || c.title.en || '';
    }
    if (c.description && typeof c.description === 'object') {
      c.description = c.description.fr || c.description.ar || c.description.en || '';
    }
    return c;
  });
}

function generateManifestJSON() {
  var docs = getManifestDocuments();
  return {
    meta: { project: 'inry-biblio', generatedAt: new Date().toISOString(), docCount: docs.length },
    documents: docs
  };
}

function downloadManifestJSON() {
  var manifest = generateManifestJSON();
  var blob = new Blob([JSON.stringify(manifest, null, 2)], { type: 'application/json' });
  var a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = 'manifest-inry-' + Date.now() + '.json';
  a.click();
  showToast('Manifest téléchargé.');
}

function copyManifestToClipboard() {
  var manifest = generateManifestJSON();
  navigator.clipboard.writeText(JSON.stringify(manifest, null, 2)).then(function() {
    showToast('Manifest copié dans le presse-papier.');
  }).catch(function() {
    showToast('Erreur lors de la copie.');
  });
}

function wireExportManifest() {
  var exportBtn = document.getElementById('export-manifest-btn');
  var copyBtn = document.getElementById('copy-manifest-btn');
  if (exportBtn) exportBtn.addEventListener('click', downloadManifestJSON);
  if (copyBtn) copyBtn.addEventListener('click', copyManifestToClipboard);
}

